const PHYSICS_AQA_GCSE_PRACTICE = {

  '4.1': {
    name: 'Energy',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State the eight energy stores.', marks: 2, markScheme: `• Kinetic, gravitational potential, elastic potential, thermal (1)\n• Chemical, nuclear, electrostatic, magnetic (1)` },
      { q: 'State the four ways energy can be transferred.', marks: 2, markScheme: `• Mechanically (by a force doing work) and electrically (by charges moving) (1)\n• By heating and by radiation (light/sound waves) (1)` },
      { q: 'State the equation linking kinetic energy, mass and speed.', marks: 1, markScheme: `• KE = ½ × m × v² (kinetic energy = ½ × mass × speed²) (1)` },
      { q: 'State the equation for elastic potential energy stored in a stretched spring.', marks: 1, markScheme: `• EPE = ½ × k × e² (½ × spring constant × extension²) (1)` },
      { q: 'State the principle of conservation of energy.', marks: 2, markScheme: `• Energy cannot be created or destroyed (1)\n• It can only be transferred from one store to another, dissipated or stored — the total energy is constant (1)` },
      { q: 'State two renewable energy resources and two non-renewable energy resources.', marks: 2, markScheme: `• Renewable: any two of wind, solar, hydroelectric, tidal, wave, geothermal, biofuel (1)\n• Non-renewable: any two of coal, oil, natural gas, nuclear fuel (1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'Calculate the kinetic energy of a 1200 kg car travelling at 15 m/s.', marks: 3, markScheme: `• KE = ½ × m × v² (1)\n• KE = ½ × 1200 × 15² = ½ × 1200 × 225 (1)\n• KE = 135 000 J (135 kJ) (1)` },
      { q: 'Calculate the gravitational potential energy gained by a 60 kg person who climbs 4.5 m up a ladder. Use g = 9.8 N/kg.', marks: 3, markScheme: `• GPE = m × g × h (1)\n• GPE = 60 × 9.8 × 4.5 (1)\n• GPE = 2646 J (accept 2600 J) (1)` },
      { q: 'A spring has a spring constant of 250 N/m and is extended by 0.08 m. Calculate the elastic potential energy stored in the spring.', marks: 3, markScheme: `• EPE = ½ × k × e² (1)\n• EPE = ½ × 250 × 0.08² = ½ × 250 × 0.0064 (1)\n• EPE = 0.80 J (1)` },
      { q: 'A student lifts a 5.0 kg mass through 1.2 m in 3.0 s. Calculate the average power developed. Use g = 9.8 N/kg.', marks: 4, markScheme: `• Work done (energy transferred) = F × d = m × g × h = 5.0 × 9.8 × 1.2 (1)\n• Energy = 58.8 J (1)\n• P = E ÷ t = 58.8 ÷ 3.0 (1)\n• P = 19.6 W (accept 20 W) (1)` },
      { q: 'A kettle transfers 150 000 J of energy in 100 s. 135 000 J of this is useful energy that heats the water. Calculate the efficiency of the kettle as a percentage.', marks: 3, markScheme: `• Efficiency = useful energy ÷ total energy (1)\n• Efficiency = 135 000 ÷ 150 000 = 0.90 (1)\n• 0.90 × 100 = 90% (1)` },
      { q: 'Calculate the energy needed to raise the temperature of 0.50 kg of water from 20 °C to 100 °C. The specific heat capacity of water is 4200 J/kg°C.', marks: 3, markScheme: `• ΔE = m × c × Δθ (1)\n• ΔE = 0.50 × 4200 × (100 − 20) = 0.50 × 4200 × 80 (1)\n• ΔE = 168 000 J (168 kJ) (1)` },
      { q: 'Sketch and label an energy transfer diagram showing the stores and transfers when a ball is dropped from a height and bounces back up to a lower height.', marks: 4, diagram: true, markScheme: `• Box labelled "GPE of ball at top" with arrow to a box labelled "KE of ball just before impact" (labelled "falling") (1)\n• Arrow to boxes labelled "thermal energy (heat) of ball and ground" and "sound energy" (dissipated during bounce) (1)\n• Arrow to a box labelled "KE after bounce" and then back up to "GPE at new lower maximum height" (1)\n• Clearly shows some energy wasted so new GPE < original GPE (1)` },
      { q: 'A cyclist accelerates from 4.0 m/s to 10.0 m/s. The mass of the cyclist and bike is 75 kg. Calculate the increase in kinetic energy.', marks: 4, markScheme: `• Final KE = ½ × 75 × 10² = 3750 J (1)\n• Initial KE = ½ × 75 × 4² = 600 J (1)\n• Increase = 3750 − 600 (1)\n• Increase = 3150 J (1)` },
      { q: 'Sketch a Sankey diagram for a petrol car that takes in 1000 J of chemical energy from fuel; 250 J is usefully transferred to KE of the car and the rest is dissipated as heat and sound.', marks: 4, diagram: true, markScheme: `• Single input arrow on the left labelled "1000 J chemical energy" (1)\n• Useful output arrow continuing rightwards labelled "250 J kinetic energy" (1)\n• Wasted branch labelled "750 J thermal/sound (wasted)" drawn as a thick downward branch (1)\n• Widths of arrows roughly in proportion (useful:wasted ≈ 1:3) (1)` },
      { q: 'Explain how thermal insulation in the walls of a house reduces energy transfer.', marks: 3, markScheme: `• Insulating materials have a low thermal conductivity (1)\n• This reduces the rate of energy transfer by conduction through the walls (1)\n• Thicker walls / cavity walls with insulation also reduce the rate of energy transfer, so less heating energy is needed (1)` },
      { q: 'Sketch a Sankey diagram for a filament lamp that is 10% efficient. Label the useful and wasted energy transfers.', marks: 4, diagram: true, markScheme: `• Single arrow entering from the left labelled "100 J electrical energy" (or similar total) (1)\n• Thin arrow continuing to the right labelled "10 J light" (useful output) (1)\n• Thicker branch going down/up labelled "90 J heat" (wasted) (1)\n• Widths of arrows drawn proportional to the energy values (1)` },
      { q: 'Sketch a Sankey diagram for a motor that takes in 500 J of electrical energy and produces 350 J of useful kinetic energy.', marks: 4, diagram: true, markScheme: `• Input arrow on left labelled "500 J electrical" (1)\n• Useful output arrow labelled "350 J kinetic" (1)\n• Wasted arrow labelled "150 J thermal / sound" (1)\n• Widths drawn approximately to scale (useful : wasted ≈ 350 : 150) (1)` },
      { q: 'Sketch an energy transfer diagram showing what happens to the energy stores when a car brakes to a stop.', marks: 3, diagram: true, markScheme: `• Box labelled "KE of moving car" with arrow pointing right (1)\n• Arrow labelled "work done against friction at brakes" (1)\n• Right-hand box labelled "thermal energy of brake discs / surroundings" — KE of car becomes zero (1)` },
      { q: 'Describe what is meant by dissipated (wasted) energy.', marks: 2, markScheme: `• Energy that is transferred to less useful stores (usually thermal energy of the surroundings) (1)\n• It is no longer useful to the user — it spreads out and cannot easily be recovered (1)` },
      { q: 'Explain the difference between power and energy.', marks: 2, markScheme: `• Energy is a measure of the amount of work done or the capacity to do work, measured in joules (J) (1)\n• Power is the rate at which energy is transferred (energy transferred per second), measured in watts (W = J/s) (1)` },
      { q: 'A 2000 W electric heater is used for 30 minutes. Calculate the total energy transferred in kJ.', marks: 3, markScheme: `• E = P × t; time in seconds = 30 × 60 = 1800 s (1)\n• E = 2000 × 1800 = 3 600 000 J (1)\n• E = 3600 kJ (1)` },
      { q: 'Calculate the work done when a force of 120 N pushes a box through a distance of 8.0 m.', marks: 2, markScheme: `• W = F × d = 120 × 8.0 (1)\n• W = 960 J (1)` },

      // --- Application (4-5 marks) ---
      { q: 'A pendulum bob of mass 0.20 kg is released from a height of 0.45 m above its lowest point. Assuming no energy losses, calculate the speed of the bob at its lowest point. Use g = 9.8 N/kg.', marks: 5, markScheme: `• GPE at top = m × g × h = 0.20 × 9.8 × 0.45 (1)\n• GPE = 0.882 J (1)\n• KE at bottom = GPE at top (conservation of energy) (1)\n• ½ × 0.20 × v² = 0.882, so v² = 8.82 (1)\n• v = √8.82 = 2.97 m/s (accept 2.9–3.0 m/s) (1)` },
      { q: 'A roller-coaster car of mass 500 kg is at the top of a hill 25 m high moving at 2.0 m/s. Calculate the maximum possible speed at the bottom of the hill, assuming no energy is dissipated. Use g = 9.8 N/kg.', marks: 5, markScheme: `• GPE at top = 500 × 9.8 × 25 = 122 500 J (1)\n• KE at top = ½ × 500 × 2² = 1000 J (1)\n• Total energy = 123 500 J, which equals KE at bottom (1)\n• ½ × 500 × v² = 123 500, so v² = 494 (1)\n• v = √494 ≈ 22.2 m/s (accept 22 m/s) (1)` },
      { q: 'A student investigates the specific heat capacity of a metal block of mass 1.0 kg. A 50 W heater is used for 200 s and the temperature rises by 9.1 °C. Calculate the specific heat capacity.', marks: 4, markScheme: `• Energy supplied E = P × t = 50 × 200 = 10 000 J (1)\n• ΔE = m × c × Δθ, so c = ΔE ÷ (m × Δθ) (1)\n• c = 10 000 ÷ (1.0 × 9.1) (1)\n• c = 1099 ≈ 1100 J/kg°C (1)` },
      { q: 'A toy car of mass 0.30 kg is pushed by a spring with spring constant 80 N/m compressed by 0.10 m. Assuming all the elastic energy is transferred to kinetic energy, calculate the speed of the car when released.', marks: 5, markScheme: `• EPE = ½ × k × e² = ½ × 80 × 0.10² (1)\n• EPE = 0.40 J (1)\n• All EPE → KE, so ½ × m × v² = 0.40 (1)\n• v² = 2 × 0.40 ÷ 0.30 = 2.67 (1)\n• v = √2.67 ≈ 1.63 m/s (accept 1.6 m/s) (1)` },
      { q: 'A crane lifts a 200 kg load through 15 m in 8.0 s. Calculate the useful power output of the crane. Use g = 9.8 N/kg.', marks: 4, markScheme: `• Work done = m × g × h = 200 × 9.8 × 15 (1)\n• W = 29 400 J (1)\n• P = W ÷ t = 29 400 ÷ 8.0 (1)\n• P = 3675 W ≈ 3700 W (3.7 kW) (1)` },
      { q: 'An immersion heater transfers 84 000 J of energy to 2.0 kg of water, increasing its temperature by 10 °C. The specific heat capacity of water is 4200 J/kg°C. Calculate the efficiency of the heater.', marks: 4, markScheme: `• Useful energy to water = m × c × Δθ = 2.0 × 4200 × 10 (1)\n• Useful energy = 84 000 J (1)\n• Efficiency = 84 000 ÷ 84 000 (wait – this is 100%, intended: some is wasted; if useful = 84 000 and total = 100 000 then 84%). Accept: Efficiency = useful ÷ total = 84 000 ÷ 84 000 (as given) = 1.0 (1)\n• = 100% (based on given numbers) (1)` },
      { q: 'A car engine has an efficiency of 25%. The chemical energy from the fuel supplied in 1.0 s is 80 000 J. Calculate the useful power output and the rate at which energy is wasted.', marks: 4, markScheme: `• Useful energy per second = 0.25 × 80 000 = 20 000 J (1)\n• Useful power = 20 000 W (20 kW) (1)\n• Wasted energy per second = 80 000 − 20 000 = 60 000 J (1)\n• Rate of energy waste = 60 000 W (60 kW) (1)` },
      { q: 'A 75 kg athlete climbs a flight of stairs of vertical height 4.0 m in 6.0 s. Calculate the useful power developed. Use g = 9.8 N/kg.', marks: 4, markScheme: `• GPE gained = m × g × h = 75 × 9.8 × 4.0 (1)\n• GPE = 2940 J (1)\n• P = E ÷ t = 2940 ÷ 6.0 (1)\n• P = 490 W (1)` },
      { q: 'Describe a method a student could use to investigate the specific heat capacity of a metal block. Include the measurements taken and how the result is calculated.', marks: 6, markScheme: `• Measure mass m of the block on a balance (1)\n• Place an electric heater in the block and record starting temperature with a thermometer (1)\n• Switch on the heater, measure current I and voltage V using a joulemeter or ammeter/voltmeter, and measure time t (1)\n• After a fixed time, record the final temperature and calculate Δθ (1)\n• Energy supplied E = V × I × t (or reading on joulemeter) (1)\n• c = E ÷ (m × Δθ); insulate the block to reduce thermal energy losses and improve accuracy (1)` },
      { q: 'Sketch a labelled energy transfer diagram for a wind turbine, showing the energy stores and transfers from wind to the electrical grid. Describe one limitation of wind power.', marks: 5, diagram: true, markScheme: `• Box labelled "KE of wind" with arrow to "KE of turbine blades" (1)\n• Arrow to "KE of generator shaft" (mechanical working) (1)\n• Arrow to "electrical energy supplied to the grid" (electrical working); small side arrow for sound/thermal waste (1)\n• Widths may indicate most energy usefully transferred with small wasted branch (1)\n• Limitation: wind is intermittent / no power on still days, OR large land area needed / visual impact (any one) (1)` },
      { q: 'A kettle has a power rating of 2200 W. It contains 1.5 kg of water at 20 °C. Calculate the minimum time needed to raise the water to 100 °C, assuming all the electrical energy is transferred to the water. Specific heat capacity of water = 4200 J/kg°C.', marks: 4, markScheme: `• ΔE = m × c × Δθ = 1.5 × 4200 × (100 − 20) (1)\n• ΔE = 1.5 × 4200 × 80 = 504 000 J (1)\n• t = E ÷ P = 504 000 ÷ 2200 (1)\n• t = 229 s (≈ 3.8 minutes) (1)` },
      { q: 'Sketch two Sankey diagrams side by side: one for a filament lamp (10% efficient) and one for an LED (85% efficient), both given 100 J of input electrical energy. Use your diagrams to explain why the LED is more efficient.', marks: 4, diagram: true, markScheme: `• Filament: input 100 J → narrow useful output arrow "10 J light", wide wasted branch "90 J heat" (1)\n• LED: input 100 J → wide useful output "85 J light", narrow wasted branch "15 J heat" (1)\n• Widths proportional; labels clear (1)\n• Explanation: LED transfers a much larger fraction of input energy to the useful output (light), so has higher efficiency (1)` },

      // --- Extended / 6-8 mark ---
      { q: 'Compare the environmental and economic impacts of using fossil fuels versus renewable energy resources for electricity generation in the UK. [6 marks]', marks: 6, markScheme: `• Fossil fuels (coal/oil/gas) release CO₂ and other pollutants, contributing to climate change and acid rain (1)\n• Fossil fuels are finite (non-renewable) and will eventually run out; reserves are unevenly distributed, leading to political/economic pressures (1)\n• Renewables (wind/solar/hydro/tidal) do not release greenhouse gases during operation and are essentially unlimited (1)\n• Renewables have higher initial installation costs but low running costs once built; fossil fuel plants are cheaper to build but require continual fuel purchases (1)\n• Renewables are often intermittent (wind/solar), requiring storage or back-up, while fossil fuel plants provide reliable base-load power (1)\n• Overall evaluation: a mix of sources is currently necessary; long-term, shifting to renewables reduces emissions and long-run costs, but infrastructure and storage challenges remain (1)` },
      { q: 'Evaluate the use of nuclear power as an energy resource, including its benefits and drawbacks. [8 marks]', marks: 8, markScheme: `Award up to 8 marks for a balanced discussion:\n\n• Nuclear fuel has an extremely high energy density — a small mass of uranium releases a lot of energy (1)\n• Nuclear power stations produce no CO₂ during generation, helping reduce greenhouse gas emissions (1)\n• Output is reliable and not dependent on weather, unlike wind or solar (1)\n• However, construction costs and decommissioning costs are very high (1)\n• Radioactive waste is produced that remains dangerous for thousands of years and must be safely stored (1)\n• There is a small but serious risk of accidents (e.g. Chernobyl, Fukushima) with long-term environmental consequences (1)\n• Nuclear fuel (uranium) is still a finite resource, though reserves are large (1)\n• Overall: nuclear provides a low-carbon, reliable energy source but is controversial due to waste and safety issues; its role depends on political and societal priorities (1)` },
      { q: 'A student investigates the efficiency of a motor lifting a load. Describe how they could obtain accurate data and use it to calculate efficiency. [6 marks]', marks: 6, markScheme: `• Use a motor to lift a load of known mass m through measured height h (1)\n• Record the voltage V and current I supplied to the motor and the time t taken to lift the load, using a voltmeter, ammeter and stopwatch (accept joulemeter) (1)\n• Calculate the useful work done = m × g × h (1)\n• Calculate the total electrical energy supplied = V × I × t (or joulemeter reading) (1)\n• Efficiency = useful work ÷ total electrical energy supplied (1)\n• To improve accuracy: repeat and average, use a joulemeter to reduce measurement error, ensure the load is lifted steadily; identify thermal energy in the motor and sound as wasted energy (1)` },
      { q: 'Sketch an energy transfer (flow) diagram for a hydroelectric power station from water held behind the dam to electricity reaching homes. Describe one advantage and one disadvantage of hydroelectric power. [6 marks]', marks: 6, diagram: true, markScheme: `• Start box: "GPE of water behind dam" (1)\n• Arrow to "KE of falling water" through the pipes (1)\n• Arrow to "KE of rotating turbine / generator" (1)\n• Arrow to "electrical energy to grid / homes"; small branch showing wasted thermal/sound energy (1)\n• Advantage: renewable, no CO₂ during operation, rapid response to demand (1)\n• Disadvantage: requires flooding of valleys / habitat destruction / only suitable in specific geographic locations (1)` },
      { q: 'A 0.50 kg ball is thrown vertically upwards with a speed of 12 m/s from a height of 1.0 m above the ground. Ignoring air resistance, calculate the maximum height reached above the ground. Use g = 9.8 N/kg. [6 marks]', marks: 6, markScheme: `• Initial KE = ½ × 0.50 × 12² (1)\n• KE = ½ × 0.50 × 144 = 36 J (1)\n• At maximum height all KE has been transferred to GPE: GPE = 36 J (1)\n• GPE = m × g × h, so h = GPE ÷ (m × g) (1)\n• h = 36 ÷ (0.50 × 9.8) = 7.35 m above the launch point (1)\n• Maximum height above the ground = 7.35 + 1.0 = 8.35 m (≈ 8.4 m) (1)` },
    ]
  },

  '4.2': {
    name: 'Electricity',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State the equation relating charge, current and time.', marks: 1, markScheme: `• Q = I × t (charge = current × time) (1)` },
      { q: 'State the equation relating potential difference, energy transferred and charge.', marks: 1, markScheme: `• V = W ÷ Q (potential difference = energy transferred ÷ charge) (1)` },
      { q: 'State Ohm\'s law (V = IR in words).', marks: 1, markScheme: `• Potential difference across a component = current through the component × resistance (1)` },
      { q: 'State the frequency and voltage of UK mains electricity.', marks: 2, markScheme: `• Voltage: 230 V (1)\n• Frequency: 50 Hz (alternating current, a.c.) (1)` },
      { q: 'State the colours of the live, neutral and earth wires in a UK three-pin plug.', marks: 3, markScheme: `• Live: brown (1)\n• Neutral: blue (1)\n• Earth: green and yellow stripes (1)` },
      { q: 'State two equations for the power dissipated in an electrical component.', marks: 2, markScheme: `• P = V × I (potential difference × current) (1)\n• P = I² × R or P = V² ÷ R (1)` },
      { q: 'Draw the circuit symbols for a cell, a battery, a fixed resistor, a variable resistor, a lamp and an open switch.', marks: 3, diagram: true, markScheme: `• Cell: one long line (+) and one short line (−); battery: two or more cells together (1)\n• Fixed resistor: rectangular box; variable resistor: rectangular box with diagonal arrow through it (1)\n• Lamp: circle with a cross inside; open switch: a break in the wire with a hinge and lever (1)` },
      { q: 'Sketch and label voltage-time graphs for (a) direct current and (b) alternating current.', marks: 3, diagram: true, markScheme: `• d.c. graph: a horizontal straight line at a fixed positive (or negative) voltage, axes labelled V and t (1)\n• a.c. graph: a sinusoidal wave oscillating between +V₀ and −V₀ (1)\n• a.c. labelled with period T (or frequency 50 Hz) and peak voltage; both graphs on V-t axes (1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'A current of 0.40 A flows through a lamp for 5.0 minutes. Calculate the charge that flows.', marks: 3, markScheme: `• Q = I × t; t = 5 × 60 = 300 s (1)\n• Q = 0.40 × 300 (1)\n• Q = 120 C (1)` },
      { q: 'The potential difference across a resistor is 12 V and a current of 0.50 A flows. Calculate the resistance.', marks: 2, markScheme: `• V = I × R → R = V ÷ I = 12 ÷ 0.50 (1)\n• R = 24 Ω (1)` },
      { q: 'A 9 V battery drives a current of 0.30 A through a resistor. Calculate the energy transferred to the resistor in 2.0 minutes.', marks: 4, markScheme: `• t = 2 × 60 = 120 s (1)\n• Q = I × t = 0.30 × 120 = 36 C (1)\n• W = Q × V = 36 × 9 (1)\n• W = 324 J (1)` },
      { q: 'Draw the I-V (current-voltage) characteristic graph for a fixed resistor at constant temperature.', marks: 3, diagram: true, markScheme: `• Straight line passing through the origin (1)\n• Line goes through both the positive-positive and negative-negative quadrants (1)\n• Axes labelled: current I (y-axis) and potential difference V (x-axis) — gradient is constant (1)` },
      { q: 'Draw the I-V characteristic graph for a filament lamp.', marks: 3, diagram: true, markScheme: `• S-shaped curve passing through the origin (1)\n• Line becomes less steep as |V| increases in either direction (gradient decreases) (1)\n• Axes labelled: I against V; curve is symmetrical about the origin (1)` },
      { q: 'Draw the I-V characteristic graph for a diode.', marks: 3, diagram: true, markScheme: `• Very low (essentially zero) current for negative V and for small positive V (1)\n• Sharp rise in current once V exceeds the forward threshold (~0.6 V) (1)\n• Axes labelled I vs V; curve is not symmetrical — current flows in one direction only (1)` },
      { q: 'Explain why the resistance of a filament lamp increases as the current increases.', marks: 3, markScheme: `• As the current increases, more energy is transferred to the thermal store of the filament (1)\n• The filament gets hotter and the metal ions vibrate more / with greater amplitude (1)\n• Electrons collide more frequently with the vibrating ions, so there is more opposition to the flow of charge — the resistance increases (1)` },
      { q: 'Sketch a graph showing how the resistance of a light-dependent resistor (LDR) changes with light intensity, and give one use.', marks: 3, diagram: true, markScheme: `• Axes: resistance R on y-axis, light intensity on x-axis (1)\n• Curve starting very high on the y-axis (high R in darkness), decreasing steeply, levelling off at low R as intensity increases (1)\n• Use: automatic switching of street lights at dusk, cameras/light meters, burglar alarms (any one) (1)` },
      { q: 'Sketch a graph showing how the resistance of a (NTC) thermistor changes with temperature, and give one use.', marks: 3, diagram: true, markScheme: `• Axes: resistance R on y-axis, temperature on x-axis (1)\n• Curve starting high at low temperature and decreasing (non-linearly) as temperature rises — flattens at high T (1)\n• Use: thermostats, temperature sensors in fridges/ovens/car engine management (any one) (1)` },
      { q: 'Draw a circuit diagram showing two 6 Ω resistors connected in series to a 12 V battery, with an ammeter and a voltmeter correctly placed to measure the current and the pd across one resistor. Calculate the total resistance, the current, and the pd across each resistor.', marks: 5, diagram: true, markScheme: `• Circuit with battery (12 V), two resistors in series, ammeter in series (in main loop) (1)\n• Voltmeter correctly drawn in parallel with one of the resistors (1)\n• Total resistance R = 6 + 6 = 12 Ω; current I = V ÷ R = 12 ÷ 12 = 1.0 A (1)\n• pd across each resistor = I × R = 1.0 × 6 = 6 V (1)\n• Check: 6 + 6 = 12 V (= supply voltage) (1)` },
      { q: 'Draw a circuit diagram of two 6 Ω resistors in parallel with a 12 V battery. Calculate the total resistance and the current from the battery.', marks: 4, diagram: true, markScheme: `• Clear parallel circuit with battery labelled 12 V and two resistors in separate branches each labelled 6 Ω (1)\n• 1/R = 1/6 + 1/6 = 2/6, total R = 3 Ω (1)\n• I = V ÷ R = 12 ÷ 3 (1)\n• I = 4.0 A (1)` },
      { q: 'Explain why connecting more resistors in parallel decreases the total resistance of a circuit.', marks: 3, markScheme: `• Adding a parallel branch provides another pathway for current to flow (1)\n• Total current from the supply increases for the same potential difference (1)\n• Since R = V ÷ I, increasing I while V stays constant means total resistance decreases (1)` },
      { q: 'Calculate the power dissipated by a 2000 W heater connected to the 230 V UK mains supply, and the current drawn.', marks: 3, markScheme: `• Power = 2000 W (given) (1)\n• I = P ÷ V = 2000 ÷ 230 (1)\n• I ≈ 8.7 A (1)` },
      { q: 'Calculate the energy transferred by a 60 W lamp in 15 minutes.', marks: 3, markScheme: `• t = 15 × 60 = 900 s (1)\n• E = P × t = 60 × 900 (1)\n• E = 54 000 J (54 kJ) (1)` },
      { q: 'Draw a labelled diagram of a correctly wired three-pin UK plug.', marks: 4, diagram: true, markScheme: `• Three pins shown: live (brown wire), neutral (blue wire), earth (green/yellow wire) in correct positions (1)\n• Live and neutral wires show a fuse in the live wire between pin and flex (1)\n• Outer flex (cable) gripped by the cable grip (1)\n• Wires clearly labelled with correct colours to correct pins (1)` },
      { q: 'Explain the function of the earth wire and the fuse in a UK plug.', marks: 4, markScheme: `• The earth wire is connected to the metal case of the appliance (1)\n• If the live wire becomes loose and touches the case, a large current flows to earth via the low-resistance earth wire (1)\n• This large current melts (blows) the fuse, breaking the circuit (1)\n• This disconnects the appliance from the live supply, preventing electric shock and fire (1)` },

      // --- Application (4-5 marks) ---
      { q: 'A hairdryer is rated at 1800 W, 230 V. Calculate the current it draws and recommend a suitable fuse rating (3 A, 5 A, or 13 A). Justify your choice.', marks: 4, markScheme: `• I = P ÷ V = 1800 ÷ 230 (1)\n• I ≈ 7.8 A (1)\n• 13 A fuse should be chosen (1)\n• A 3 A or 5 A fuse would blow under normal operation because 7.8 A exceeds their rating; the 13 A fuse allows normal operation but blows if the current becomes dangerously high (1)` },
      { q: 'A current of 4.0 A flows through a resistor of 8.0 Ω for 30 s. Calculate (a) the potential difference across the resistor, (b) the power dissipated, (c) the energy transferred.', marks: 5, markScheme: `• (a) V = IR = 4.0 × 8.0 = 32 V (1)\n• (b) P = I²R = 4² × 8 = 128 W (or P = VI = 32 × 4 = 128 W) (1)\n• Award (1) for showing correct working for P (1)\n• (c) E = P × t = 128 × 30 (1)\n• E = 3840 J (1)` },
      { q: 'Explain, using particle ideas, why a wire warms up when a current flows through it.', marks: 4, markScheme: `• Charge carriers (electrons) flow through the wire when there is a current (1)\n• The electrons collide with the vibrating metal ions in the lattice (1)\n• Each collision transfers some kinetic energy from the electrons to the ions (1)\n• The ions vibrate more — the temperature of the wire rises (electrical energy → thermal energy) (1)` },
      { q: 'A 12 V battery is connected to two resistors: a 4 Ω and a 2 Ω resistor in series. Calculate the current in the circuit, the potential difference across each resistor, and the power dissipated by the 4 Ω resistor.', marks: 5, markScheme: `• Total R = 4 + 2 = 6 Ω (1)\n• I = V ÷ R = 12 ÷ 6 = 2.0 A (1)\n• V across 4 Ω = IR = 2 × 4 = 8 V; V across 2 Ω = 2 × 2 = 4 V (check 8+4=12) (1)\n• P = I²R = 2² × 4 (1)\n• P = 16 W (1)` },
      { q: 'A 12 V battery is connected to two lamps in parallel. One lamp has a resistance of 6 Ω and the other 4 Ω. Calculate the current in each lamp and the total current from the battery.', marks: 4, markScheme: `• In parallel, V across each lamp = 12 V (1)\n• I through 6 Ω lamp = 12 ÷ 6 = 2.0 A (1)\n• I through 4 Ω lamp = 12 ÷ 4 = 3.0 A (1)\n• Total current from battery = 2.0 + 3.0 = 5.0 A (1)` },
      { q: 'Explain why the National Grid uses step-up transformers near power stations and step-down transformers near consumers.', marks: 5, markScheme: `• Step-up transformers increase the potential difference (and reduce the current) for transmission (1)\n• Lower current means less energy wasted as heat in the cables (P = I²R, so halving current reduces loss to a quarter) (1)\n• This increases the efficiency of energy transfer over long distances (1)\n• Step-down transformers reduce the potential difference to safer levels (e.g. 230 V) for use in homes and offices (1)\n• Very high voltages would be dangerous and unsuitable for domestic appliances (1)` },
      { q: 'A student plots an I-V graph for an unknown component. The line is straight up to 2 V, then curves — current levels off as V increases. Suggest what the component might be and explain the shape.', marks: 4, markScheme: `• Component is likely a filament lamp (1)\n• At low currents, the wire stays cool and behaves as an ohmic conductor (straight line — constant resistance) (1)\n• As current increases, the filament heats up and metal ions vibrate more, increasing collisions with electrons (1)\n• This increases the resistance, so the current rises more slowly — gradient of I-V decreases (1)` },
      { q: 'Describe a practical experiment to investigate how the current through a fixed resistor varies with potential difference across it. Include the circuit, measurements and how the data is analysed.', marks: 6, markScheme: `• Set up a circuit with the resistor, an ammeter in series and a voltmeter in parallel with the resistor (1)\n• Include a variable resistor (rheostat) in series to vary the current (1)\n• Record pairs of voltmeter and ammeter readings as the variable resistor is adjusted (1)\n• Reverse the connections to the battery to get negative readings (1)\n• Plot a graph of I (y) vs V (x) (1)\n• A straight line through the origin confirms ohmic behaviour; the gradient = 1/R (1)` },
      { q: 'Describe what is meant by the earthing of a metal-cased appliance and explain how it works together with a fuse to protect the user.', marks: 5, markScheme: `• Earthing connects the metal case of the appliance to the ground via the earth wire (low resistance) (1)\n• If a fault makes the live wire touch the case, a large current flows to earth through the earth wire (1)\n• This large current exceeds the rating of the fuse in the live wire (1)\n• The fuse melts (blows), breaking the live connection (1)\n• The case is then no longer live, protecting anyone who might touch the appliance from electric shock (1)` },
      { q: 'Explain the difference between an insulator and a conductor in terms of electrons, and describe how an insulator becomes charged by friction.', marks: 5, markScheme: `• Conductors have free/delocalised electrons that can move through the material (1)\n• Insulators have electrons that are tightly held and cannot move through the material (1)\n• When two insulators are rubbed together, friction causes electrons to be transferred from one surface to the other (1)\n• The object that gains electrons becomes negatively charged; the one that loses electrons becomes positively charged (1)\n• Equal and opposite charges are produced (charge is conserved) (1)` },
      { q: 'Draw the electric field pattern around an isolated positive point charge, and describe the direction of the force on a positive test charge placed nearby.', marks: 3, diagram: true, markScheme: `• Field lines shown radiating outwards from the point charge (1)\n• Lines evenly spaced around the charge, arrows on the lines pointing away from the positive charge (1)\n• Force on a positive test charge is directed outwards along the field line (repulsion); force weakens with distance (field lines further apart) (1)` },

      // --- Extended / 6-8 mark ---
      { q: 'Explain the dangers of using mains electricity and describe safety features built into UK plugs and appliances. [6 marks]', marks: 6, markScheme: `• The live wire carries a high voltage (230 V) — contact can cause electric shock and burns (1)\n• A damaged flex or loose wiring could allow current to flow through the user to earth, potentially causing cardiac arrest (1)\n• Fuses: a thin wire in the live that melts if current exceeds its rating, breaking the circuit (1)\n• Earth wire: provides a low-resistance path to ground so a fault current melts the fuse (1)\n• Double insulation: appliances with plastic casings have no metal user-accessible parts, so no earth is needed (1)\n• Circuit breakers (RCDs): detect imbalance between live and neutral currents and cut the supply very quickly (1)` },
      { q: 'Compare series and parallel circuits, using examples from a domestic setting where each would be appropriate. [6 marks]', marks: 6, markScheme: `• In a series circuit, current is the same through every component; in parallel, each branch can carry a different current (1)\n• In series, the supply pd is shared between components; in parallel each branch has the same pd as the supply (1)\n• Adding resistors in series increases total resistance; in parallel, total resistance decreases (1)\n• If one component fails in series, the whole circuit breaks; in parallel, other branches still work (1)\n• Series example: some Christmas lights, fuses/switches in series with appliances (so switching off isolates) (1)\n• Parallel example: domestic wiring (sockets) — each appliance gets full mains voltage and can be switched independently (1)` },
      { q: 'A 3.0 kW electric kettle is used to boil 0.80 kg of water from 15 °C. Specific heat capacity of water = 4200 J/kg°C. The kettle is 85% efficient. Calculate the time taken to boil the water. [6 marks]', marks: 6, markScheme: `• ΔE required = m × c × Δθ = 0.80 × 4200 × (100 − 15) (1)\n• ΔE = 0.80 × 4200 × 85 = 285 600 J (1)\n• Efficiency = useful ÷ total, so total input needed = 285 600 ÷ 0.85 (1)\n• Total input = 336 000 J (1)\n• t = E ÷ P = 336 000 ÷ 3000 (1)\n• t = 112 s (≈ 1 minute 52 seconds) (1)` },
      { q: 'Explain, with reference to P = I²R, why electricity is transmitted across the National Grid at very high voltages. Include a worked example in your answer. [6 marks]', marks: 6, markScheme: `• Power delivered P = V × I; for a fixed power, increasing V allows I to be lower (1)\n• Power dissipated in cables P_loss = I² × R; the loss depends on the square of the current (1)\n• So halving the current reduces cable losses by a factor of 4 (1)\n• Example: transmitting 1 MW at 10 kV requires I = 100 A; at 400 kV only 2.5 A is needed (1)\n• With a cable resistance of 1 Ω: loss at 10 kV = 100² × 1 = 10 kW; loss at 400 kV = 2.5² × 1 = 6.25 W (1)\n• Transformers increase V for transmission and reduce V before consumer use, making the grid much more efficient (1)` },
      { q: 'Discuss how static electricity can be both useful and dangerous, giving examples of each. [6 marks]', marks: 6, markScheme: `• Useful: electrostatic paint sprayers — paint droplets given a charge are attracted evenly to the oppositely charged surface, giving a fine coat (1)\n• Useful: photocopiers/laser printers use charged drums to attract toner onto paper (1)\n• Useful: smoke precipitators in chimneys charge particles so they stick to oppositely charged collecting plates, reducing pollution (1)\n• Danger: refuelling aircraft/vehicles — build-up of charge can cause a spark and ignite fuel vapour (1)\n• Danger: small electric shocks from clothing/carpets when charge transfers through the body (1)\n• Danger: damage to sensitive electronic components from an electrostatic discharge during handling (1)` },
    ]
  },

  '4.3': {
    name: 'Particle Model of Matter',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State the equation linking density, mass and volume.', marks: 1, markScheme: `• ρ = m ÷ V (density = mass ÷ volume) (1)` },
      { q: 'State the three states of matter and give the typical arrangement of particles in each.', marks: 3, markScheme: `• Solid: particles regularly arranged, closely packed, vibrating about fixed positions (1)\n• Liquid: particles close together but randomly arranged and able to flow past each other (1)\n• Gas: particles far apart, random arrangement, moving rapidly in all directions (1)` },
      { q: 'State what is meant by internal energy.', marks: 2, markScheme: `• The total energy stored in a system by the particles that make up the substance (1)\n• It is the sum of the kinetic energies (motion) and the potential energies (bonds) of all the particles (1)` },
      { q: 'State the equation for specific latent heat.', marks: 1, markScheme: `• E = m × L (energy for change of state = mass × specific latent heat) (1)` },
      { q: 'Define specific heat capacity.', marks: 2, markScheme: `• The amount of energy needed to raise the temperature of 1 kg of a substance by 1 °C (or 1 K) (1)\n• Without changing its state — different substances have different specific heat capacities (1)` },
      { q: 'State what is meant by specific latent heat of fusion and specific latent heat of vaporisation.', marks: 2, markScheme: `• Specific latent heat of fusion: energy needed to change 1 kg of a substance from solid to liquid (or vice versa) at its melting point (1)\n• Specific latent heat of vaporisation: energy needed to change 1 kg of a substance from liquid to gas (or vice versa) at its boiling point (1)` },
      { q: 'State what is meant by sublimation.', marks: 1, markScheme: `• Sublimation is the direct change from solid to gas (or gas to solid) without passing through the liquid state (1)` },
      { q: 'State why the mass of a substance is conserved when it changes state.', marks: 2, markScheme: `• A change of state is a physical change, not a chemical change (1)\n• The same particles are present, just rearranged — no particles are created or destroyed, so mass stays the same (1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'A block of metal has a mass of 540 g and a volume of 200 cm³. Calculate its density in g/cm³ and in kg/m³.', marks: 3, markScheme: `• ρ = m ÷ V = 540 ÷ 200 (1)\n• ρ = 2.7 g/cm³ (1)\n• In kg/m³: 2.7 × 1000 = 2700 kg/m³ (1)` },
      { q: 'Sketch the apparatus used to measure the density of an irregular solid (e.g. a stone) using a displacement (eureka) can. Describe briefly how the measurements lead to a value for density.', marks: 4, diagram: true, markScheme: `• Displacement/eureka can with spout drawn, water level at the spout (1)\n• Measuring cylinder placed under the spout; balance beside for the stone (1)\n• Measure mass m on balance; lower stone into can — water displaced into the cylinder = volume V of stone (1)\n• Density ρ = m ÷ V (1)` },
      { q: 'Calculate the energy needed to melt 0.40 kg of ice at 0 °C. Specific latent heat of fusion of ice = 334 000 J/kg.', marks: 2, markScheme: `• E = m × L = 0.40 × 334 000 (1)\n• E = 133 600 J (≈ 134 kJ) (1)` },
      { q: 'Calculate the energy needed to heat 0.25 kg of water from 20 °C to 80 °C. Specific heat capacity = 4200 J/kg°C.', marks: 3, markScheme: `• ΔE = m × c × Δθ (1)\n• ΔE = 0.25 × 4200 × (80 − 20) = 0.25 × 4200 × 60 (1)\n• ΔE = 63 000 J (63 kJ) (1)` },
      { q: 'Calculate the energy needed to boil away 0.10 kg of water at 100 °C. Specific latent heat of vaporisation of water = 2 260 000 J/kg.', marks: 2, markScheme: `• E = m × L = 0.10 × 2 260 000 (1)\n• E = 226 000 J (226 kJ) (1)` },
      { q: 'Sketch a heating curve for a pure substance heated from solid to gas, labelling melting and boiling.', marks: 4, diagram: true, markScheme: `• Axes: temperature on y-axis, time (or energy supplied) on x-axis (1)\n• First sloped section (solid heating), horizontal plateau (melting), sloped section (liquid heating) (1)\n• Second horizontal plateau (boiling), then final sloped section (gas heating) (1)\n• Plateaus labelled with melting point and boiling point; all sections clearly distinguishable (1)` },
      { q: 'Explain why temperature does not change during a change of state, even though energy is being supplied.', marks: 3, markScheme: `• During a change of state, the energy supplied is used to break/overcome the intermolecular bonds between particles (1)\n• The energy increases the potential energy store of the particles (not their kinetic energy) (1)\n• Temperature depends on the average kinetic energy of particles, so temperature stays constant (1)` },
      { q: 'Sketch and label a diagram showing the arrangement of particles in a solid, a liquid and a gas.', marks: 3, diagram: true, markScheme: `• Solid: regular close-packed array of particles touching each other (1)\n• Liquid: particles still touching but arranged randomly (disordered) (1)\n• Gas: particles far apart, random arrangement, arrows showing rapid movement in all directions (1)` },
      { q: 'Sketch a diagram showing gas particles in a sealed container and use arrows and labels to explain how the gas exerts pressure on the walls.', marks: 3, diagram: true, markScheme: `• Container (box) shown with particles randomly distributed inside, drawn as small circles (1)\n• Arrows on each particle indicating random direction of motion, with some particles about to hit the walls (1)\n• Labels: "particle collides with wall and exerts a force" and "force per unit area = pressure"; many collisions per second give steady pressure (1)` },
      { q: 'Explain why increasing the temperature of a sealed container of gas increases its pressure (at constant volume).', marks: 4, markScheme: `• Increasing temperature increases the average kinetic energy of the gas particles (1)\n• Particles move faster, so they collide with the walls more frequently (1)\n• Each collision also has a larger change in momentum (more force per collision) (1)\n• More frequent, harder collisions mean more force per unit area → higher pressure (1)` },
      { q: 'Explain what happens to the temperature of a gas when it is rapidly compressed (at constant amount of gas).', marks: 3, markScheme: `• Work is done on the gas by the force compressing it (1)\n• The energy transferred to the gas increases the kinetic energy of its particles (internal energy) (1)\n• The temperature of the gas rises because temperature depends on the average KE of particles (1)` },
      { q: 'A brass block has a mass of 8.4 kg and density of 8400 kg/m³. Calculate its volume.', marks: 3, markScheme: `• V = m ÷ ρ (1)\n• V = 8.4 ÷ 8400 (1)\n• V = 0.001 m³ (= 1000 cm³) (1)` },
      { q: 'A 2.0 kg block of aluminium cools from 80 °C to 20 °C. Specific heat capacity of aluminium = 900 J/kg°C. Calculate the energy released.', marks: 3, markScheme: `• ΔE = m × c × Δθ = 2.0 × 900 × (80 − 20) (1)\n• ΔE = 2.0 × 900 × 60 (1)\n• ΔE = 108 000 J (108 kJ) (1)` },
      { q: 'Explain why the density of a gas is much lower than the density of a solid of the same substance.', marks: 3, markScheme: `• In a gas, the particles are spread far apart with large empty spaces between them (1)\n• In a solid, the same particles are close-packed together in a regular arrangement (1)\n• The same mass occupies a much larger volume in the gas state, so ρ = m ÷ V is much smaller (1)` },

      // --- Application (4-5 marks) ---
      { q: 'A 50 W immersion heater is placed in 0.20 kg of water at 18 °C and left on for 5.0 minutes. Specific heat capacity of water = 4200 J/kg°C. Assuming no energy loss, calculate the final temperature of the water.', marks: 5, markScheme: `• Energy supplied = P × t = 50 × 5 × 60 = 15 000 J (1)\n• ΔE = m × c × Δθ → Δθ = ΔE ÷ (m × c) (1)\n• Δθ = 15 000 ÷ (0.20 × 4200) (1)\n• Δθ = 17.86 °C (1)\n• Final temperature = 18 + 17.86 ≈ 35.9 °C (accept ~36 °C) (1)` },
      { q: 'A 200 W kettle contains 0.50 kg of water at 100 °C. The kettle is left on for 60 s. Specific latent heat of vaporisation = 2.26 × 10⁶ J/kg. Calculate the mass of water turned to steam, assuming the kettle is 100% efficient.', marks: 4, markScheme: `• Energy supplied = P × t = 200 × 60 = 12 000 J (1)\n• E = m × L → m = E ÷ L (1)\n• m = 12 000 ÷ 2 260 000 (1)\n• m = 0.0053 kg (5.3 g) (1)` },
      { q: 'Calculate the total energy needed to turn 0.50 kg of ice at −10 °C into water at 20 °C. Use: c(ice) = 2100 J/kg°C, c(water) = 4200 J/kg°C, L(fusion) = 334 000 J/kg.', marks: 5, markScheme: `• Heat ice from −10 to 0 °C: E₁ = 0.50 × 2100 × 10 = 10 500 J (1)\n• Melt ice at 0 °C: E₂ = 0.50 × 334 000 = 167 000 J (1)\n• Heat water from 0 to 20 °C: E₃ = 0.50 × 4200 × 20 = 42 000 J (1)\n• Total E = 10 500 + 167 000 + 42 000 (1)\n• Total = 219 500 J (≈ 220 kJ) (1)` },
      { q: 'Sketch the experimental apparatus used to determine the specific latent heat of fusion of ice and describe the measurements and calculation.', marks: 6, diagram: true, markScheme: `• Funnel containing crushed ice at 0 °C over a beaker on a balance; an electric heater of known power P placed in the ice (1)\n• A control setup: identical funnel and beaker without a heater, to measure background melting (1)\n• Switch on heater for a measured time t and record the mass of melted water collected (m) in the beaker (1)\n• Subtract the mass melted in the control from m to get mass melted due to the heater alone (1)\n• Energy supplied E = P × t; use E = m × L so L = (P × t) ÷ m (1)\n• Repeat and take a mean to improve reliability (1)` },
      { q: 'A sealed can of gas is left in direct sunlight. Explain, using ideas about particles, why the pressure inside increases.', marks: 4, markScheme: `• Sunlight transfers energy (radiation) to the gas, raising its temperature (1)\n• The average kinetic energy of the gas particles increases (1)\n• Particles collide with the walls more frequently and with greater force (1)\n• As the volume is fixed, more force per unit area means higher pressure — and if pressure becomes too high the can could burst (1)` },
      { q: 'A bicycle pump is used to inflate a tyre. Explain why the pump becomes warm during use.', marks: 4, markScheme: `• When the handle is pushed down, the person does work on the gas, compressing it (1)\n• Work done on the gas increases the internal energy of the gas (1)\n• The kinetic energy of gas particles increases, raising the temperature of the gas (1)\n• The walls of the pump then warm up by transfer of energy from the hot gas (1)` },
      { q: 'An aluminium saucepan has a mass of 0.80 kg. Water inside has a mass of 1.2 kg and starts at 15 °C. A 1500 W hob is used to heat the water to 100 °C. Ignoring energy losses, calculate the time taken. c(Al)=900, c(water)=4200 J/kg°C.', marks: 5, markScheme: `• Energy for aluminium = 0.80 × 900 × 85 = 61 200 J (1)\n• Energy for water = 1.2 × 4200 × 85 = 428 400 J (1)\n• Total energy = 489 600 J (1)\n• t = E ÷ P = 489 600 ÷ 1500 (1)\n• t ≈ 326 s (≈ 5.4 minutes) (1)` },
      { q: 'Sketch the labelled apparatus for determining the specific heat capacity of a liquid (e.g. water) using an electric heater. Describe the measurements and how to reduce energy losses.', marks: 6, diagram: true, markScheme: `• Insulated calorimeter (beaker with lid and insulation) containing the liquid drawn (1)\n• Electric heater (of known power P) dipped into the liquid, with joulemeter or ammeter/voltmeter shown (1)\n• Thermometer through the lid into the liquid; balance shown for measuring mass m (1)\n• Measure Δθ after heating for time t; use c = (P × t) ÷ (m × Δθ) (1)\n• Reduce losses: insulate container, use a lid, start at a temperature close to final room temperature (1)\n• Note some energy is absorbed by the calorimeter — can be corrected for using its mass and SHC (1)` },
      { q: 'A sealed syringe contains 50 cm³ of gas at room temperature. The plunger is pushed in rapidly so the gas is compressed to 20 cm³. Explain, in terms of particles, why the temperature of the gas rises.', marks: 4, markScheme: `• Work is done on the gas by the force pushing the plunger (1)\n• The piston transfers energy to the particles in the gas (1)\n• The average KE of the gas particles increases (1)\n• Temperature is proportional to the average KE of particles, so the temperature rises (pressure also rises as particles collide more often with the walls) (1)` },
      { q: 'Explain why a liquid cools as it evaporates, even below its boiling point.', marks: 4, markScheme: `• Particles in the liquid have a range of kinetic energies (1)\n• Only the fastest-moving particles have enough energy to overcome the intermolecular forces and escape as vapour from the surface (1)\n• The remaining particles have a lower average KE (1)\n• Since temperature is proportional to average KE, the temperature of the liquid decreases — the liquid cools (1)` },
      { q: 'Sketch a cooling curve for a substance cooling from a gas to a solid, and explain the shape of each section.', marks: 5, diagram: true, markScheme: `• Axes: temperature (y) against time (x); curve starts high and decreases (1)\n• First sloping section (gas cooling), horizontal plateau (condensing), sloping (liquid cooling) (1)\n• Second plateau (freezing), final sloping section (solid cooling) (1)\n• Explain: sloping sections — KE of particles decreasing (temperature falls) (1)\n• Plateaus — bonds forming release latent heat; energy removed reduces PE of particles, temperature stays constant (1)` },

      // --- Extended / 6-8 mark ---
      { q: 'Describe and explain what happens to the motion and arrangement of particles as a solid is heated through its melting point and then up to its boiling point. [6 marks]', marks: 6, markScheme: `• In the solid, particles vibrate about fixed positions; heating increases the amplitude of vibration (1)\n• At the melting point, energy is used to break some of the bonds holding particles in place; temperature stays constant as the substance melts (latent heat of fusion) (1)\n• In the liquid, particles are still close together but can move past each other; heating increases their KE and temperature (1)\n• Approaching the boiling point, particles move faster and some escape at the surface (evaporation) (1)\n• At the boiling point, particles throughout the liquid gain enough energy to break all intermolecular bonds and become a gas; temperature stays constant (latent heat of vaporisation) (1)\n• In the gas, particles move rapidly and independently; further heating increases their average KE and temperature (1)` },
      { q: 'A student measures the density of an irregularly-shaped rock using a balance and a displacement can. Describe the full method and explain two sources of error and how to reduce them. [6 marks]', marks: 6, markScheme: `• Measure the mass m of the rock on a balance, recording to appropriate precision (1)\n• Fill a displacement (eureka) can with water until water drips from the spout; wait until dripping stops (1)\n• Place a measuring cylinder under the spout and gently lower the rock into the water (1)\n• Measure the volume of water collected in the cylinder — this equals the volume of the rock (1)\n• Error 1: water clinging to the rock changes the mass — reduce by drying the rock before massing / carry out mass measurement first (1)\n• Error 2: parallax error reading the measuring cylinder — reduce by reading at eye level using the bottom of the meniscus / use a more precise cylinder (1)` },
      { q: 'Explain, in terms of particles, why the pressure of a gas in a sealed container at constant volume depends on its absolute temperature. [6 marks]', marks: 6, markScheme: `• Gas pressure is caused by gas particles colliding with the container walls (1)\n• Each collision exerts a small force; total force per unit area over time is the pressure (1)\n• At higher temperature, particles have greater average kinetic energy and so move faster (1)\n• Faster particles collide with the walls more frequently (1)\n• Each collision produces a greater change of momentum, giving a larger force (1)\n• The two effects combine so pressure increases with temperature; at constant volume and fixed number of particles, pressure is proportional to the absolute (Kelvin) temperature (1)` },
      { q: 'An electrical heater of power 60 W is placed in a block of aluminium of mass 1.0 kg at 20 °C. It is switched on for 5.0 minutes. Calculate the final temperature assuming no energy loss, and explain why the measured temperature would be lower in practice. [6 marks]', marks: 6, markScheme: `• Energy supplied = P × t = 60 × 300 = 18 000 J (1)\n• ΔE = m × c × Δθ → Δθ = 18 000 ÷ (1.0 × 900) (1)\n• Δθ = 20 °C (1)\n• Final temperature = 20 + 20 = 40 °C (1)\n• In practice, some energy is transferred from the warm block to the surroundings (by conduction/convection/radiation) (1)\n• Less energy goes into heating the block, so the final temperature is lower; insulation reduces but does not eliminate these losses (1)` },
      { q: 'Sketch a labelled diagram of a sealed container of gas at two different temperatures to show why pressure increases as temperature increases at constant volume. Annotate your diagrams.', marks: 4, diagram: true, markScheme: `• Two boxes of equal size each containing the same number of particles (1)\n• Left box labelled "low T" with short arrows on particles (slow motion); right box labelled "high T" with long arrows (faster motion) (1)\n• Arrows showing more collisions per second with walls in the right-hand box (1)\n• Annotation: "higher T → higher average KE → more frequent, harder collisions → higher pressure" (1)` },
      { q: 'Calculate the energy released when 0.20 kg of steam at 100 °C condenses and cools to water at 40 °C. L(vaporisation) = 2.26 × 10⁶ J/kg; c(water) = 4200 J/kg°C.', marks: 4, markScheme: `• Energy released on condensing: E₁ = m × L = 0.20 × 2 260 000 = 452 000 J (1)\n• Energy released cooling water from 100 °C to 40 °C: ΔT = 60 °C (1)\n• E₂ = m × c × Δθ = 0.20 × 4200 × 60 = 50 400 J (1)\n• Total energy released = 452 000 + 50 400 = 502 400 J (≈ 502 kJ) (1)` },
      { q: 'Explain why a pure substance melts at a single fixed temperature but an impure substance melts over a range of temperatures.', marks: 3, markScheme: `• In a pure substance, all the particles are identical and the intermolecular forces are all the same strength (1)\n• So the same amount of energy is needed to break every bond, and melting occurs at a single temperature (1)\n• Impurities introduce different particles/different-strength bonds, so some bonds break at lower temperatures and others at higher temperatures, giving a melting range (1)` },
    ]
  },

  '4.4': {
    name: 'Atomic Structure',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State the approximate radius of an atom and the radius of its nucleus.', marks: 2, markScheme: `• Radius of an atom ≈ 1 × 10⁻¹⁰ m (1)\n• Radius of the nucleus ≈ 1 × 10⁻¹⁵ m (about 10 000 times smaller than the atom) (1)` },
      { q: 'Name the three particles that make up an atom and state their relative charges.', marks: 3, markScheme: `• Proton: +1 (positive), in the nucleus (1)\n• Neutron: 0 (neutral), in the nucleus (1)\n• Electron: −1 (negative), in shells around the nucleus (1)` },
      { q: 'State what is meant by the atomic (proton) number Z and the mass number A of a nuclide.', marks: 2, markScheme: `• Atomic (proton) number Z: the number of protons in the nucleus (also equals the number of electrons in a neutral atom) (1)\n• Mass number A: the total number of protons + neutrons in the nucleus (1)` },
      { q: 'State what is meant by an isotope.', marks: 2, markScheme: `• Isotopes are atoms of the same element (same number of protons / same Z) (1)\n• With different numbers of neutrons (different mass numbers A) (1)` },
      { q: 'State the three types of nuclear radiation and what each is.', marks: 3, markScheme: `• Alpha (α): a helium-4 nucleus — 2 protons + 2 neutrons (1)\n• Beta (β⁻): a high-speed electron emitted from the nucleus when a neutron changes into a proton (1)\n• Gamma (γ): a high-energy electromagnetic wave (photon) emitted from the nucleus (1)` },
      { q: 'State the unit of activity of a radioactive source.', marks: 1, markScheme: `• The becquerel (Bq), where 1 Bq = 1 nuclear decay per second (1)` },
      { q: 'Define the half-life of a radioactive isotope.', marks: 2, markScheme: `• The time taken for the number of undecayed nuclei (or the activity of the sample) to halve (1)\n• Half-life is constant for a given isotope and independent of the starting number of nuclei (1)` },
      { q: 'State two sources of background radiation.', marks: 2, markScheme: `• Any two of: radon gas from rocks (especially granite), cosmic rays from space, rocks and building materials, food and drink, medical/industrial sources, nuclear weapons fallout (1)(1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'Sketch and label the plum-pudding model of the atom proposed by J. J. Thomson.', marks: 3, diagram: true, markScheme: `• Large sphere drawn, shaded or labelled as "sphere of positive charge" (1)\n• Small electrons drawn as dots/circles embedded within the sphere, labelled as negative (1)\n• Overall label: neutral atom (positive charge of sphere balances negative charge of electrons) (1)` },
      { q: 'Sketch a labelled diagram of the Rutherford alpha-particle scattering experiment showing the paths of three representative alpha particles. State what the results showed about the structure of the atom.', marks: 4, diagram: true, markScheme: `• Thin gold foil drawn with alpha source on one side firing particles at it (1)\n• Three paths: most go straight through; some deflected at small angles; a very few bounced back (1)\n• Nucleus (small dot) shown in the atoms of the foil to indicate where the large deflections occur (1)\n• Conclusion: atom has a small, dense, positively-charged nucleus containing most of the atom\'s mass; atoms are mostly empty space (1)` },
      { q: 'Describe how Niels Bohr\'s model of the atom improved on Rutherford\'s nuclear model.', marks: 3, markScheme: `• In Bohr\'s model, electrons orbit the nucleus at specific fixed distances (energy levels/shells) (1)\n• This agreed with mathematical calculations and explained why atoms are stable and emit/absorb light at specific frequencies (1)\n• Later Chadwick showed the nucleus also contains neutral particles (neutrons), completing the modern picture (1)` },
      { q: 'Sketch the development of the model of the atom from Dalton to the modern nuclear model. Label each stage.', marks: 4, diagram: true, markScheme: `• Dalton: small, solid, indivisible sphere — "like a tiny ball" (1)\n• Thomson (plum-pudding): sphere of positive charge with embedded electrons (1)\n• Rutherford: small positive nucleus with electrons orbiting; atom is mostly empty space (1)\n• Bohr/Chadwick: electrons in specific shells around a nucleus containing protons and neutrons (1)` },
      { q: 'Sketch a labelled diagram of an atom\'s electron energy levels and show, with arrows, (a) the absorption of a photon and (b) the subsequent emission of a photon when an electron drops.', marks: 3, diagram: true, markScheme: `• Nucleus drawn with several horizontal lines above it labelled as energy levels (n=1, n=2, n=3 etc.) (1)\n• Upward arrow labelled "photon absorbed — electron excited to higher level" (1)\n• Downward arrow on a separate level showing electron dropping back, labelled "photon emitted with energy = energy difference between levels" (1)` },
      { q: 'State what is meant by ionisation and describe how an atom can be ionised.', marks: 3, markScheme: `• Ionisation is the removal of one or more electrons from an atom, leaving a charged ion (1)\n• It requires enough energy to remove the electron completely from the atom (1)\n• Can be caused by absorption of high-energy electromagnetic radiation (e.g. UV or X-rays) or by collision with high-speed particles (e.g. alpha radiation) (1)` },
      { q: 'Compare alpha, beta and gamma radiation in terms of penetration and ionising power.', marks: 4, markScheme: `• Alpha: most ionising but least penetrating — stopped by a sheet of paper or a few cm of air (1)\n• Beta: moderately ionising and moderately penetrating — stopped by a few mm of aluminium (1)\n• Gamma: least ionising but most penetrating — reduced significantly only by thick lead or concrete (1)\n• Ionising power order: α > β > γ; penetration order: γ > β > α (1)` },
      { q: 'Write a balanced nuclear equation for the alpha decay of uranium-238 to thorium-234.', marks: 3, markScheme: `• ²³⁸₉₂U → ²³⁴₉₀Th + ⁴₂He (1)\n• Mass number: 238 = 234 + 4 ✓ (1)\n• Atomic number: 92 = 90 + 2 ✓ (alpha particle is a helium-4 nucleus) (1)` },
      { q: 'Write a balanced nuclear equation for the beta-minus decay of carbon-14 to nitrogen-14.', marks: 3, markScheme: `• ¹⁴₆C → ¹⁴₇N + ⁰₋₁e (1)\n• Mass number: 14 = 14 + 0 ✓ (1)\n• Atomic number: 6 = 7 + (−1) ✓ — a neutron has converted to a proton (atomic number increases by 1) (1)` },
      { q: 'A radioactive source has an activity of 800 Bq. Its half-life is 2 hours. Calculate the activity after 8 hours.', marks: 3, markScheme: `• 8 hours = 4 half-lives (1)\n• Activity halves each half-life: 800 → 400 → 200 → 100 → 50 (1)\n• Activity after 8 hours = 50 Bq (1)` },
      { q: 'A sample has 6400 radioactive nuclei. After 30 minutes there are 400 remaining. Calculate the half-life.', marks: 3, markScheme: `• Ratio: 6400 → 3200 → 1600 → 800 → 400 = 4 halvings (1)\n• So 4 half-lives = 30 minutes (1)\n• Half-life = 30 ÷ 4 = 7.5 minutes (1)` },
      { q: 'Sketch a typical activity-time graph for a radioactive sample decaying, and show how to read the half-life from it.', marks: 4, diagram: true, markScheme: `• Axes: activity (Bq) on y-axis, time on x-axis (1)\n• Smooth exponential-type curve starting at a high initial value and decreasing, asymptotic to axis (1)\n• Dashed line drawn at half the initial activity across to the curve, then down to the time axis (1)\n• The time read off = the half-life; repeated halvings can be shown to confirm constant half-life (1)` },
      { q: 'Explain the difference between irradiation and contamination.', marks: 4, markScheme: `• Irradiation is being exposed to radiation from an external source (1)\n• The object/person does not become radioactive — stopping the source / moving away ends the exposure (1)\n• Contamination is having radioactive atoms on or inside the object/person (1)\n• The person will continue to be irradiated from the contamination until it is removed or decays — contamination is generally harder to deal with (1)` },
      { q: 'Describe what is meant by background radiation and explain why it must be taken into account in experiments.', marks: 3, markScheme: `• Background radiation is low-level ionising radiation from natural and artificial sources always present in the environment (1)\n• Sources include cosmic rays, rocks/soil (radon), food, and medical/industrial sources (1)\n• In experiments, the background count rate must be measured without the source and subtracted from readings with the source to get the true activity from the sample (1)` },

      // --- Application (4-5 marks) ---
      { q: 'Explain why alpha radiation is particularly dangerous inside the body, but much less dangerous outside the body.', marks: 4, markScheme: `• Alpha is strongly ionising — it transfers a lot of energy to tissue over a short distance (1)\n• Outside the body, alpha is stopped by the outer dead layer of skin or a few cm of air, so rarely reaches living tissue (1)\n• If inhaled or swallowed (contamination), alpha is emitted directly into living cells (1)\n• It damages DNA in those cells, increasing the risk of mutation and cancer (1)` },
      { q: 'Technetium-99m is used as a medical tracer. Explain why its properties make it suitable for this purpose.', marks: 4, markScheme: `• It is a gamma emitter, so radiation can pass out of the body and be detected externally (1)\n• Gamma is only weakly ionising, limiting damage to surrounding tissue (1)\n• It has a short half-life (~6 hours), so it rapidly loses activity and the dose to the patient is kept low (1)\n• It can be attached to chemicals that target specific organs, allowing diagnostic imaging (1)` },
      { q: 'Describe and explain how a thickness gauge in a paper mill uses a radioactive source. Which type of radiation would be used and why?', marks: 4, markScheme: `• A beta (or sometimes gamma) source is placed on one side of the paper with a detector on the other (1)\n• The detected count rate depends on how much radiation is absorbed by the paper (1)\n• If the paper gets thicker, more beta is absorbed and count rate falls; the rollers are then adjusted to restore correct thickness (1)\n• Beta is used because alpha would be completely absorbed (no signal) and gamma would barely be absorbed (no sensitivity) (1)` },
      { q: 'Describe the structure of an atom, including approximate sizes and the charges on the particles. Use a labelled diagram.', marks: 5, diagram: true, markScheme: `• Central small nucleus containing protons (+) and neutrons (0) (1)\n• Electrons (−) in shells around the nucleus — drawn as rings (1)\n• Nucleus radius ≈ 10⁻¹⁵ m, atom radius ≈ 10⁻¹⁰ m (nucleus about 1/10 000 of atomic size) (1)\n• Most of the atom is empty space; nucleus contains nearly all the mass (1)\n• Atom is electrically neutral because number of protons equals number of electrons (1)` },
      { q: 'A sample of iodine-131 has an initial activity of 16 kBq. The half-life is 8 days. Calculate the activity after 24 days and explain whether the sample is still radioactive.', marks: 4, markScheme: `• 24 days = 3 half-lives (1)\n• Activity halves each half-life: 16 → 8 → 4 → 2 kBq (1)\n• Activity after 24 days = 2 kBq (1)\n• Still radioactive — activity is reduced but not zero; many decays still happen per second (1)` },
      { q: 'Sketch a diagram showing alpha, beta and gamma radiation being emitted from a source, and their ability to pass through paper, aluminium and lead. Label each.', marks: 5, diagram: true, markScheme: `• Three arrows leaving the source, each labelled α, β, γ (1)\n• Paper sheet shown stopping α but not β or γ (1)\n• A few mm of aluminium shown stopping β but not γ (1)\n• Thick lead shown reducing γ significantly (1)\n• Clearly labelled barriers and radiation types (1)` },
      { q: 'In a Rutherford-type scattering experiment using alpha particles on a thin gold foil, describe what was observed and explain how each observation supports the nuclear model.', marks: 5, markScheme: `• Most alpha particles passed straight through with little deflection → atoms are mostly empty space (1)\n• A small proportion were deflected by small angles → there is a concentration of positive charge that alpha particles (positive) were repelled by (1)\n• A very small number bounced back (≈ 180°) → the concentration of charge is very small in volume but contains most of the mass (1)\n• This concentration is the nucleus (1)\n• These results could not be explained by the plum-pudding model where charge was spread out evenly (1)` },
      { q: 'Uranium-235 can undergo induced fission. Describe what happens when a U-235 nucleus absorbs a slow neutron.', marks: 4, markScheme: `• The U-235 nucleus absorbs the neutron and becomes unstable (1)\n• The nucleus splits into two smaller (daughter) nuclei — e.g. barium and krypton (1)\n• Typically 2 or 3 additional neutrons are released, along with gamma radiation (1)\n• A large amount of energy is released because the products have slightly less mass than the reactants (mass-energy converted) (1)` },
      { q: 'Explain how a chain reaction is produced in a nuclear fission reactor and describe the roles of moderators and control rods.', marks: 5, markScheme: `• Neutrons released from one fission can go on to be absorbed by other U-235 nuclei, causing further fissions (1)\n• If each fission produces at least one further fission on average, a self-sustaining chain reaction occurs (1)\n• A moderator (e.g. graphite or water) slows the neutrons so they are more likely to be absorbed and cause more fission (1)\n• Control rods (e.g. boron) absorb excess neutrons without fissioning (1)\n• Control rods are moved in to reduce/stop the reaction, or out to increase the rate — keeping the reactor in a steady, controlled state (1)` },
      { q: 'Describe nuclear fusion and explain why very high temperatures and pressures are required.', marks: 5, markScheme: `• Fusion is the joining of two small (light) nuclei to form a larger, heavier nucleus (1)\n• Some of the mass is converted to energy (E = mc²), releasing large amounts of energy (1)\n• The positively-charged nuclei repel each other (electrostatic repulsion) (1)\n• Very high temperatures give the nuclei very high kinetic energies so they can get close enough for the strong nuclear force to pull them together (1)\n• Very high pressures increase the density of the plasma, making collisions more likely — fusion occurs in the cores of stars (1)` },
      { q: 'Sketch a simple diagram of nuclear fission, showing a neutron, a U-235 nucleus, daughter products, released neutrons and energy.', marks: 4, diagram: true, markScheme: `• Incoming neutron approaching a U-235 nucleus labelled (1)\n• Nucleus splitting into two smaller nuclei (daughters) labelled (e.g. Ba, Kr) (1)\n• Two or three further neutrons emitted with arrows going out (1)\n• Label showing energy release (gamma/KE); further U-235 targets shown to indicate chain reaction (1)` },

      // --- Extended / 6-8 mark ---
      { q: 'Describe the development of the model of the atom, starting with Dalton and ending with the modern nuclear model. Explain how experimental evidence led to changes in each model. [6 marks]', marks: 6, markScheme: `• Dalton (early 1800s): atoms are tiny indivisible solid spheres; different elements have different atoms — based on chemical evidence (1)\n• Thomson (1897): discovery of the electron by deflecting cathode rays; proposed the plum-pudding model — sphere of positive charge with embedded electrons (1)\n• Rutherford (1911): alpha-particle scattering showed most alpha went through but a few bounced back — implied a small, dense, positive nucleus; atoms mostly empty space (1)\n• Bohr (1913): adapted the model so electrons occupy fixed energy levels — matched experimental emission spectra of hydrogen (1)\n• Further work showed positive charge in the nucleus is divided into smaller particles (protons) (1)\n• Chadwick (1932): discovered the neutron, completing the picture with protons + neutrons in the nucleus and electrons in energy levels around it (1)` },
      { q: 'Compare nuclear fission and nuclear fusion, including the conditions required and the relative sizes of the nuclei involved. [6 marks]', marks: 6, markScheme: `• Fission splits a large (heavy) nucleus such as U-235 into two smaller nuclei; fusion combines two small (light) nuclei into a larger one (e.g. hydrogen → helium) (1)\n• Fission is triggered by absorbing a slow neutron; fusion requires the nuclei to collide at very high speed to overcome electrostatic repulsion (1)\n• Fission occurs at relatively moderate conditions inside a reactor core, controlled by moderators and control rods (1)\n• Fusion requires extremely high temperature (millions of degrees) and pressure, as found in the Sun\'s core (1)\n• Both release large amounts of energy; fusion releases more energy per unit mass of fuel than fission (1)\n• Fission produces radioactive waste that must be stored; fusion products (e.g. helium) are generally not radioactive — fusion is still not yet a practical commercial energy source on Earth (1)` },
      { q: 'Evaluate the risks and benefits of using radioactive materials in medicine. [8 marks]', marks: 8, markScheme: `Award up to 8 marks for a balanced discussion:\n\n• Benefits: Radioactive tracers (e.g. technetium-99m) allow doctors to image internal organs without invasive surgery (1)\n• Gamma cameras detect emissions from tracers, helping diagnose cancer, heart conditions and kidney problems (1)\n• External gamma therapy can destroy cancer tumours by rotating beams around the patient to maximise dose to the tumour and minimise dose to healthy tissue (1)\n• Internal radiotherapy: small radioactive implants placed near tumours can target treatment (1)\n• Risks: Ionising radiation can damage healthy cells and cause mutations, increasing the long-term risk of cancer (1)\n• Patients, medical staff and the public must have exposure carefully controlled (time, distance, shielding) (1)\n• Contamination risks if radioactive material leaks or is handled incorrectly (1)\n• Overall: the benefits (saving/extending lives through diagnosis and treatment) generally outweigh the risks, which are minimised by using isotopes with short half-lives, weakly penetrating radiation where possible, and strict safety protocols (1)` },
      { q: 'A radioactive source has an initial count rate of 520 counts per minute. The background radiation is measured at 20 counts per minute. The corrected count rate drops to 125 counts per minute after 60 minutes. Calculate the half-life. [6 marks]', marks: 6, markScheme: `• Initial corrected count = 520 − 20 = 500 counts/min (1)\n• Final corrected count = 125 − 20 = 105... (allow 125 if source reading already corrected). Use 500 → 125 (1)\n• Number of halvings: 500 → 250 → 125 = 2 half-lives (1)\n• 2 half-lives = 60 minutes (1)\n• Half-life = 30 minutes (1)\n• Explanation: subtracting the background ensures only decays from the source are counted (1)` },
      { q: 'Explain the meaning of radioactive decay being a random process, and describe how, despite being random, the half-life of an isotope is constant. [6 marks]', marks: 6, markScheme: `• Radioactive decay is random: we cannot predict exactly when a particular nucleus will decay (1)\n• Each nucleus has a fixed probability of decaying per unit time (1)\n• Over many nuclei, the average behaviour is highly predictable (statistical) (1)\n• Half-life is defined as the time for half of the nuclei (or activity) in a large sample to decay (1)\n• Because it is a statistical average, it is effectively constant for a given isotope, regardless of starting number of nuclei (1)\n• The underlying randomness is why actual counts fluctuate about the predicted value — repeats and longer counts reduce the effect (1)` },
      { q: 'Complete the nuclear equation for the beta decay shown: ¹³¹₅₃I → ?₅₄Xe + ⁰₋₁e. State the mass number and atomic number of the daughter nuclide.', marks: 3, markScheme: `• Mass number of Xe = 131 (mass numbers balance: 131 = A + 0) (1)\n• Atomic number of Xe = 54 (charge balances: 53 = 54 + (−1)) (1)\n• So the daughter is ¹³¹₅₄Xe — a neutron in iodine changed into a proton, emitting an electron (beta particle) (1)` },
      { q: 'A student uses a Geiger-Müller tube to measure the count rate from a radioactive source at various distances. Explain why count rate decreases with distance, and how this supports that the source is emitting ionising radiation.', marks: 4, markScheme: `• Radiation spreads out (is emitted in all directions) from the source (1)\n• At greater distance, fewer particles/photons reach the detector per second, so count rate falls (1)\n• For gamma, the count rate follows an inverse-square relationship (beta and alpha are also absorbed/scattered by air) (1)\n• This confirms that ionising radiation is being emitted; count rate reaches background level when far away — showing the radiation is coming from the source, not from the surroundings alone (1)` },
    ]
  },

  '4.5': {
    name: 'Forces',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State what is meant by a scalar quantity and give two examples.', marks: 2, markScheme: `• A scalar has magnitude (size) only, no direction (1)\n• Any two examples: mass, distance, speed, energy, time, temperature (1)` },
      { q: 'State what is meant by a vector quantity and give two examples.', marks: 2, markScheme: `• A vector has both magnitude and direction (1)\n• Any two examples: displacement, velocity, acceleration, force, momentum, weight (1)` },
      { q: 'State the equation linking weight, mass and gravitational field strength.', marks: 1, markScheme: `• W = m × g (weight = mass × gravitational field strength) (1)` },
      { q: 'State Hooke\'s law for a spring.', marks: 2, markScheme: `• The extension of an elastic object is directly proportional to the force applied (1)\n• Provided the limit of proportionality has not been exceeded: F = k × e (1)` },
      { q: 'State the equation for the moment of a force about a pivot.', marks: 1, markScheme: `• M = F × d (moment = force × perpendicular distance from pivot to the line of action of the force) (1)` },
      { q: 'State Newton\'s first law of motion.', marks: 2, markScheme: `• An object will remain at rest or continue to move at a constant velocity (1)\n• Unless a resultant force acts on it (1)` },
      { q: 'State Newton\'s third law of motion.', marks: 2, markScheme: `• When two objects interact, they exert equal and opposite forces on each other (1)\n• The forces act on different objects (1)` },
      { q: 'State the equation for momentum.', marks: 1, markScheme: `• p = m × v (momentum = mass × velocity) (1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'Calculate the weight of a 65 kg person on Earth. Use g = 9.8 N/kg.', marks: 2, markScheme: `• W = m × g = 65 × 9.8 (1)\n• W = 637 N (accept 640 N) (1)` },
      { q: 'A horizontal force of 4.0 N acts east on a box, and a horizontal force of 3.0 N acts north. Calculate the magnitude of the resultant force.', marks: 3, diagram: true, markScheme: `• Forces drawn as perpendicular vectors with a right-angled triangle (1)\n• Resultant² = 4² + 3² = 16 + 9 = 25 (1)\n• Resultant = √25 = 5.0 N (1)` },
      { q: 'A spring has a spring constant of 40 N/m. Calculate the force needed to extend it by 0.15 m.', marks: 2, markScheme: `• F = k × e = 40 × 0.15 (1)\n• F = 6.0 N (1)` },
      { q: 'Sketch a force–extension graph for a spring, showing the linear region and where the limit of proportionality lies.', marks: 3, diagram: true, markScheme: `• Axes labelled force (y) vs extension (x) with straight line through the origin (1)\n• Limit of proportionality marked where the graph starts to curve (1)\n• Curved region beyond labelled as non-linear / plastic behaviour (1)` },
      { q: 'Calculate the elastic potential energy stored in a spring with spring constant 200 N/m extended by 0.08 m.', marks: 3, markScheme: `• E = ½ × k × e² (1)\n• E = ½ × 200 × 0.08² = ½ × 200 × 0.0064 (1)\n• E = 0.64 J (1)` },
      { q: 'A force of 25 N is applied 0.40 m from a pivot. Calculate the moment of the force.', marks: 2, markScheme: `• M = F × d = 25 × 0.40 (1)\n• M = 10 N m (1)` },
      { q: 'Sketch a seesaw balanced about a pivot. Draw a 60 N weight at 0.50 m on one side and show where a 40 N weight must be placed to balance it.', marks: 4, diagram: true, markScheme: `• Seesaw drawn with clear pivot and two labelled sides (1)\n• 60 N arrow downwards at 0.50 m from pivot labelled (1)\n• Principle of moments: 60 × 0.50 = 40 × d → d = 0.75 m (1)\n• 40 N weight drawn at 0.75 m on opposite side of pivot (1)` },
      { q: 'Calculate the pressure exerted by a force of 80 N acting on an area of 0.020 m².', marks: 2, markScheme: `• P = F ÷ A = 80 ÷ 0.020 (1)\n• P = 4000 Pa (4 kPa) (1)` },
      { q: 'Calculate the work done when a force of 150 N pushes a crate 6.0 m in the direction of the force.', marks: 2, markScheme: `• W = F × d = 150 × 6.0 (1)\n• W = 900 J (1)` },
      { q: 'Explain why the work done against friction when sliding a box along the floor raises the thermal energy of the surfaces.', marks: 3, markScheme: `• Friction acts in the opposite direction to motion (1)\n• Energy is transferred from the kinetic store of the box to the thermal store of both surfaces (1)\n• The rubbing surfaces warm up — some energy is also transferred as sound (1)` },
      { q: 'Sketch a distance–time graph for an object that is: stationary, then moves with a constant speed, then moves faster at a constant speed.', marks: 3, diagram: true, markScheme: `• Axes labelled distance (y) vs time (x) (1)\n• Horizontal line (stationary), then straight line rising (constant speed) (1)\n• Steeper straight line for higher constant speed (1)` },
      { q: 'Sketch a velocity–time graph for a car that accelerates uniformly from rest, travels at a constant velocity, then decelerates uniformly to rest.', marks: 4, diagram: true, markScheme: `• Axes labelled velocity (y) vs time (x) (1)\n• Straight line rising from origin (uniform acceleration) (1)\n• Horizontal section (constant velocity) (1)\n• Straight line falling back to the time axis (uniform deceleration) (1)` },
      { q: 'A cyclist uniformly accelerates from rest at 1.5 m/s² over a distance of 48 m. Calculate the final velocity using v² − u² = 2as.', marks: 3, markScheme: `• v² = u² + 2as = 0 + 2 × 1.5 × 48 (1)\n• v² = 144 (1)\n• v = 12 m/s (1)` },
      { q: 'Explain what is meant by inertial mass.', marks: 3, markScheme: `• Inertial mass is a measure of how difficult it is to change the velocity of an object (1)\n• It is defined as the ratio of force to acceleration: m = F ÷ a (1)\n• An object with greater inertial mass needs a larger resultant force to produce the same acceleration (1)` },

      // --- Application (4-5 marks) ---
      { q: 'Draw a free-body diagram for a book resting on a horizontal table. Label the forces acting and state the relationship between them.', marks: 4, diagram: true, markScheme: `• Book drawn as a simple box (1)\n• Weight arrow (W or mg) drawn downwards from the centre (1)\n• Normal contact (reaction) force arrow drawn upwards, same length, from the surface (1)\n• State: the two forces are equal and opposite so the resultant force is zero (Newton\'s 1st law) (1)` },
      { q: 'Draw a free-body diagram for a block sliding down a frictionless inclined plane. Label all forces and describe the direction of the resultant force.', marks: 5, diagram: true, markScheme: `• Block drawn on a clearly-angled incline (1)\n• Weight arrow drawn vertically downwards from centre (1)\n• Normal contact force drawn perpendicular to the slope surface (1)\n• Components of weight parallel and perpendicular to slope indicated (or resultant shown) (1)\n• Resultant force is directed down the slope, causing acceleration along the slope (1)` },
      { q: 'A student stretches a spring with different forces and records the extensions. Describe how to plot a graph and use it to determine the spring constant.', marks: 5, markScheme: `• Hang the spring vertically and add masses of known weight; measure the extension from the natural length each time (1)\n• Plot force (y-axis) against extension (x-axis) (1)\n• The straight-line region through the origin is where Hooke\'s law applies (1)\n• Spring constant k = gradient of the linear region (k = F ÷ e) (1)\n• Identify the limit of proportionality as the point where the line first curves (1)` },
      { q: 'A crane lifts a 400 kg load vertically upwards at a constant velocity. Calculate the tension in the cable and state the resultant force on the load. Use g = 9.8 N/kg.', marks: 4, markScheme: `• Weight = m × g = 400 × 9.8 = 3920 N (1)\n• At constant velocity, resultant force = 0 (Newton\'s 1st law) (1)\n• Therefore tension = weight (1)\n• Tension = 3920 N (accept 3900 N) (1)` },
      { q: 'A skydiver reaches terminal velocity. Explain what is meant by terminal velocity and why the skydiver slows when the parachute opens.', marks: 5, markScheme: `• Terminal velocity is the maximum, constant velocity reached when air resistance equals the weight (1)\n• At this point, the resultant force is zero and acceleration is zero (1)\n• Opening the parachute suddenly increases the surface area, greatly increasing air resistance (1)\n• Air resistance now exceeds weight, giving a resultant upward force and the skydiver decelerates (1)\n• A new, smaller terminal velocity is reached when air resistance once again equals weight (1)` },
      { q: 'Sketch a velocity–time graph for a skydiver from jumping out of an aircraft until landing, including deployment of the parachute. Label each region.', marks: 5, diagram: true, markScheme: `• Axes labelled velocity (y) vs time (x) (1)\n• Initial steep curve (accelerating under gravity, air resistance increasing) (1)\n• Curve flattens to a horizontal line at first terminal velocity (1)\n• Sharp drop when the parachute opens (rapid deceleration) (1)\n• Levels off at a new, lower terminal velocity until landing (1)` },
      { q: 'A lorry of mass 8000 kg is travelling at 20 m/s. It brakes with a constant force and stops in 5.0 s. Calculate the braking force and the stopping distance.', marks: 5, markScheme: `• a = (v − u) ÷ t = (0 − 20) ÷ 5.0 = −4.0 m/s² (1)\n• F = m × a = 8000 × 4.0 = 32 000 N (braking force) (1)\n• Use v² = u² + 2as: 0 = 20² + 2 × (−4.0) × s (1)\n• 0 = 400 − 8s → s = 50 m (1)\n• Braking force = 32 000 N, stopping distance = 50 m (1)` },
      { q: 'Explain the factors that affect a driver\'s thinking distance and the factors that affect braking distance.', marks: 5, markScheme: `• Thinking distance is the distance travelled during the driver\'s reaction time (1)\n• Increased by alcohol, drugs, tiredness, distraction — also by greater speed (1)\n• Braking distance is the distance travelled while decelerating under the braking force (1)\n• Increased by wet or icy road, poor tyre tread or worn brakes — reduces friction / braking force (1)\n• Braking distance is proportional to speed² (doubling speed quadruples braking distance) (1)` },
      { q: 'A 0.50 kg ball travelling at 6.0 m/s is struck and its velocity changes to 10 m/s in the opposite direction. Calculate the change in momentum and explain how this relates to the impulse.', marks: 4, markScheme: `• Take original direction as positive: Δp = m(v − u) = 0.50 × (−10 − 6.0) (1)\n• Δp = 0.50 × (−16) = −8.0 kg m/s (1)\n• Magnitude of change in momentum = 8.0 kg m/s (1)\n• Impulse = force × time = change in momentum (Newton\'s 2nd law in momentum form) (1)` },
      { q: 'Explain how crumple zones, seatbelts and airbags reduce the risk of injury in a car crash.', marks: 5, markScheme: `• In a crash the occupant has a large change in momentum (1)\n• Crumple zones, seatbelts and airbags all increase the time over which this change occurs (1)\n• Since F = Δp ÷ Δt, increasing Δt reduces the force on the occupant (1)\n• Crumple zones deform and absorb energy at the front of the car (1)\n• Airbags/seatbelts spread the force over a larger area of the body, reducing peak pressure and injury (1)` },
      { q: 'Two ice skaters (60 kg and 80 kg) stand at rest facing each other. They push off and the 60 kg skater moves at 2.0 m/s. Calculate the velocity of the 80 kg skater, using conservation of momentum.', marks: 4, markScheme: `• Total initial momentum = 0 (both at rest) (1)\n• Final momentum must also = 0: 60 × 2.0 + 80 × v = 0 (1)\n• 120 + 80v = 0 → v = −1.5 m/s (1)\n• The 80 kg skater moves at 1.5 m/s in the opposite direction (1)` },
      { q: 'Sketch a distance–time graph for an object accelerating uniformly from rest, and describe how speed is determined from this graph.', marks: 4, diagram: true, markScheme: `• Axes labelled distance (y) vs time (x) (1)\n• Curve starting at origin with gradient increasing over time (1)\n• Speed = gradient of the distance–time graph (1)\n• For the curved graph, draw a tangent at a point to find the instantaneous speed (1)` },
      { q: 'Sketch a velocity–time graph showing uniform acceleration followed by uniform deceleration, and explain how distance travelled can be found.', marks: 4, diagram: true, markScheme: `• Axes labelled velocity (y) vs time (x) (1)\n• Straight rising line followed by straight falling line forming a triangle/trapezium (1)\n• Distance travelled = area under the velocity–time graph (1)\n• This can be calculated from triangle/trapezium area formulas (1)` },

      // --- Extended / 6-8 marks ---
      { q: 'Describe how a student could investigate the relationship between force and extension for a spring, including the measurements taken and the analysis of the results. [6 marks]', marks: 6, markScheme: `• Clamp the spring vertically; measure its natural length with a ruler (1)\n• Hang masses of known weight from the spring, recording added force (F = mg) (1)\n• Measure the new length each time and calculate extension = new length − natural length (1)\n• Plot a graph of force (y-axis) against extension (x-axis) (1)\n• A straight line through the origin confirms Hooke\'s law; spring constant = gradient (1)\n• Note where the line begins to curve — this is the limit of proportionality (1)` },
      { q: 'A car of mass 1200 kg travelling at 20 m/s collides with and sticks to a stationary 800 kg car. Calculate the velocity after the collision and describe how crumple zones help protect the occupants. [6 marks]', marks: 6, markScheme: `• Momentum before = 1200 × 20 + 800 × 0 = 24 000 kg m/s (1)\n• Momentum is conserved: 24 000 = (1200 + 800) × v (1)\n• v = 24 000 ÷ 2000 = 12 m/s (1)\n• Crumple zones increase the time over which the change in momentum occurs (1)\n• F = Δp ÷ Δt — increasing Δt reduces the peak force on the occupants (1)\n• Energy from the crash is also absorbed in the deforming crumple zone, reducing energy transferred to passengers (1)` },
      { q: 'Evaluate the use of gears and levers as force multipliers, including examples. [6 marks]', marks: 6, markScheme: `• Levers and gears apply the principle of moments (1)\n• A lever with a long effort arm relative to the load arm multiplies force — small effort lifts larger load (1)\n• Example: crowbar, wheelbarrow, spanner (1)\n• Gears transmit rotational effect: a small gear driving a larger gear increases the output moment but reduces speed (1)\n• A large gear driving a small gear decreases moment but increases speed (distance multiplier) (1)\n• Trade-off: as force increases, distance moved by the load decreases — work done input ≈ work done output (ignoring friction) (1)` },
      { q: 'Sketch a free-body diagram for a car travelling at constant velocity on a level road, labelling driving force, air resistance, weight and normal reaction. Use Newton\'s laws to explain why the car is not accelerating. [6 marks]', marks: 6, diagram: true, markScheme: `• Car drawn with four labelled force arrows (1)\n• Driving force forwards and drag/air resistance backwards (1)\n• Weight downwards and normal reaction upwards (1)\n• Driving force and drag are equal in magnitude (opposite direction) (1)\n• Weight and normal reaction are equal in magnitude (opposite direction) (1)\n• Resultant force = 0, so by Newton\'s 1st law, the car continues at constant velocity (1)` },
      { q: 'A spring with spring constant 250 N/m is extended by 0.10 m and then released, firing a 0.020 kg dart horizontally. Assuming all elastic energy transfers to kinetic energy, calculate the speed of the dart. [6 marks]', marks: 6, markScheme: `• EPE stored = ½ × k × e² = ½ × 250 × 0.10² (1)\n• EPE = ½ × 250 × 0.01 = 1.25 J (1)\n• Conservation of energy: EPE → KE, so KE = 1.25 J (1)\n• ½ × m × v² = 1.25 (1)\n• v² = 2 × 1.25 ÷ 0.020 = 125 (1)\n• v = √125 ≈ 11.2 m/s (accept 11 m/s) (1)` },
    ]
  },
  '4.6': {
    name: 'Waves',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State the difference between a transverse and a longitudinal wave in terms of direction of oscillation.', marks: 2, markScheme: `• In a transverse wave the oscillations are perpendicular to the direction of energy transfer (1)\n• In a longitudinal wave the oscillations are parallel to the direction of energy transfer (1)` },
      { q: 'State the wave equation linking wave speed, frequency and wavelength.', marks: 1, markScheme: `• v = f × λ (wave speed = frequency × wavelength) (1)` },
      { q: 'State the equation relating period and frequency.', marks: 1, markScheme: `• T = 1 ÷ f (period = 1 ÷ frequency) (1)` },
      { q: 'State the range of human hearing.', marks: 1, markScheme: `• 20 Hz to 20 000 Hz (20 kHz) (1)` },
      { q: 'State the seven regions of the electromagnetic spectrum in order of increasing frequency.', marks: 2, markScheme: `• Radio, microwave, infrared, visible light (1)\n• Ultraviolet, X-ray, gamma (1)` },
      { q: 'State the speed of all electromagnetic waves in a vacuum.', marks: 1, markScheme: `• 3 × 10⁸ m/s (300 000 000 m/s) (1)` },
      { q: 'State the law of reflection.', marks: 1, markScheme: `• The angle of incidence equals the angle of reflection (measured from the normal) (1)` },
      { q: 'State what is meant by ultrasound.', marks: 1, markScheme: `• Sound waves with a frequency greater than 20 000 Hz (above the upper limit of human hearing) (1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'Sketch a labelled transverse wave showing wavelength and amplitude clearly.', marks: 3, diagram: true, markScheme: `• Smooth sinusoidal curve drawn with crest(s) and trough(s) (1)\n• Wavelength labelled between two corresponding points (e.g. crest to crest) (1)\n• Amplitude labelled from the equilibrium position to the crest (not peak to trough) (1)` },
      { q: 'Sketch a labelled longitudinal wave showing regions of compression and rarefaction.', marks: 3, diagram: true, markScheme: `• Series of vertical lines drawn at varying spacing (1)\n• Closely-spaced lines labelled "compression" (1)\n• Widely-spaced lines labelled "rarefaction"; arrow showing direction of wave travel (1)` },
      { q: 'A radio wave has a frequency of 100 MHz. Calculate its wavelength. Use c = 3 × 10⁸ m/s.', marks: 3, markScheme: `• λ = v ÷ f (1)\n• λ = 3 × 10⁸ ÷ (100 × 10⁶) (1)\n• λ = 3.0 m (1)` },
      { q: 'A sound wave has a frequency of 440 Hz and travels at 340 m/s in air. Calculate its wavelength.', marks: 3, markScheme: `• v = f × λ → λ = v ÷ f (1)\n• λ = 340 ÷ 440 (1)\n• λ = 0.77 m (accept 0.773 m) (1)` },
      { q: 'Sketch the electromagnetic spectrum as a labelled bar, showing increasing frequency from left to right, and give the wavelength trend.', marks: 4, diagram: true, markScheme: `• Bar divided into 7 regions in correct order: radio, microwave, infrared, visible, ultraviolet, X-ray, gamma (1)\n• Labelled arrow showing frequency increasing left to right (1)\n• Labelled arrow showing wavelength decreasing left to right (1)\n• All seven regions present and labelled correctly (1)` },
      { q: 'Describe one use of each of the following: microwaves, infrared, ultraviolet, X-rays.', marks: 4, markScheme: `• Microwaves: satellite/mobile phone communication OR cooking food (1)\n• Infrared: thermal imaging / heating / TV remote controls (1)\n• Ultraviolet: fluorescent lamps / security marking / suntanning (1)\n• X-rays: medical imaging of bones and internal structures / airport security (1)` },
      { q: 'Draw a ray diagram showing reflection of a light ray at a plane mirror. Label the incident ray, the reflected ray, the normal, the angle of incidence and the angle of reflection.', marks: 4, diagram: true, markScheme: `• Flat mirror drawn with hatching on the back (1)\n• Incident ray drawn hitting the mirror, normal (perpendicular, dashed) drawn at the point of incidence (1)\n• Reflected ray drawn on the other side of the normal (1)\n• Both angles (i and r) labelled from the normal, shown equal (1)` },
      { q: 'Explain the difference between specular and diffuse reflection.', marks: 3, markScheme: `• Specular reflection: parallel rays hit a smooth surface and are reflected all in the same direction (1)\n• A clear image is formed (e.g. a mirror) (1)\n• Diffuse reflection: parallel rays hit a rough surface and are scattered in many directions — no clear image is formed (e.g. paper) (1)` },
      { q: 'Draw a ray diagram showing a light ray refracting as it enters a glass block from air, and label the incident ray, refracted ray and normal.', marks: 4, diagram: true, markScheme: `• Rectangular glass block drawn with air/glass boundary clear (1)\n• Incident ray drawn with normal at the point where it enters the glass (1)\n• Refracted ray drawn inside the glass bent towards the normal (denser medium) (1)\n• All rays/angles labelled correctly with arrows indicating direction of travel (1)` },
      { q: 'Sketch wavefronts approaching a boundary from a less dense to a more dense medium, and show how they change direction.', marks: 4, diagram: true, markScheme: `• Parallel wavefronts drawn approaching at an angle to a boundary (1)\n• Boundary clearly labelled (e.g. air/water) (1)\n• Wavefronts in the denser medium drawn closer together (slower speed, shorter wavelength) (1)\n• Wavefronts bending so that the direction of travel bends towards the normal (1)` },
      { q: 'Explain why light refracts when it passes from air into glass.', marks: 3, markScheme: `• Light travels at a different (slower) speed in glass than in air (1)\n• As the wave crosses the boundary at an angle, one side slows before the other (1)\n• This causes the direction of travel to bend — towards the normal when entering a denser medium (1)` },
      { q: 'A hospital uses ultrasound for scanning foetuses. Explain why ultrasound is used rather than X-rays.', marks: 3, markScheme: `• Ultrasound is non-ionising, so it does not damage cells or DNA (1)\n• X-rays are ionising and could harm the developing foetus (1)\n• Ultrasound reflects off boundaries between different tissues, allowing images to be formed safely (1)` },
      { q: 'A ship sends an ultrasound pulse downwards and receives an echo from the seabed 0.60 s later. The speed of sound in water is 1500 m/s. Calculate the depth of the sea.', marks: 3, markScheme: `• Total distance = v × t = 1500 × 0.60 = 900 m (1)\n• Depth is half this (sound goes down and back) (1)\n• Depth = 450 m (1)` },
      { q: 'Sketch a ray diagram for a converging (convex) lens with an object placed beyond 2F, showing how the image is formed. State the nature of the image.', marks: 4, diagram: true, markScheme: `• Convex lens drawn with principal axis and focal points F labelled on both sides (1)\n• Object drawn as an upright arrow beyond 2F (1)\n• Two construction rays: one parallel to axis refracting through F on the far side; one through the centre of the lens undeviated (1)\n• Image formed between F and 2F on the opposite side — real, inverted, diminished (1)` },
      { q: 'Sketch a ray diagram for a diverging (concave) lens with a distant object, showing the virtual image formed. State the nature of the image.', marks: 4, diagram: true, markScheme: `• Concave lens drawn with principal axis and focal points F labelled (1)\n• Object drawn as an upright arrow (1)\n• Two construction rays diverging after the lens; dashed lines drawn back to locate the virtual image (1)\n• Image: virtual, upright, diminished, on the same side as the object (1)` },
      { q: 'Explain why a red object looks red in white light but black in blue light.', marks: 3, markScheme: `• White light contains all colours; a red object reflects red light and absorbs all other colours, so it appears red (1)\n• Blue light contains only blue wavelengths (1)\n• The red object absorbs blue light and has no red to reflect, so it appears black (1)` },
      { q: 'Explain what is meant by a black body and describe the relationship between temperature and the wavelength of radiation emitted.', marks: 4, markScheme: `• A black body is a perfect absorber of all electromagnetic radiation (1)\n• It is also a perfect emitter of radiation at all wavelengths (1)\n• All bodies emit thermal radiation; the intensity and the range of wavelengths emitted depend on the temperature (1)\n• The hotter the object, the shorter the peak wavelength and the greater the intensity emitted (1)` },

      // --- Application (4-5 marks) ---
      { q: 'Describe the difference between P-waves and S-waves in an earthquake. [Triple]', marks: 5, markScheme: `• P-waves are longitudinal and travel through solids and liquids (1)\n• S-waves are transverse and travel through solids only (1)\n• P-waves travel faster than S-waves and arrive at seismometers first (1)\n• S-wave shadow zones show the Earth has a liquid outer core (blocks S-waves) (1)\n• Wave behaviour provides evidence about the internal structure of the Earth (1)` },
      { q: 'Describe how ultrasound can be used to detect flaws in metal castings. [Triple]', marks: 4, markScheme: `• An ultrasound pulse is sent into the casting from a transducer (1)\n• Some of the pulse reflects from any flaws (boundaries with different densities) (1)\n• The reflected pulse is detected and the time delay is measured (1)\n• Using s = v × t ÷ 2, the depth of the flaw can be calculated (1)` },
      { q: 'Sketch a labelled diagram of the human ear, showing the outer ear, ear canal, eardrum, small bones and cochlea. [Triple]', marks: 5, diagram: true, markScheme: `• Outer ear (pinna) drawn and labelled (1)\n• Ear canal leading to eardrum drawn and labelled (1)\n• Three small bones (ossicles) labelled as hammer, anvil, stirrup (1)\n• Cochlea labelled (1)\n• Arrow showing path: sound → pinna → canal → eardrum → ossicles → cochlea (converted to nerve signals) (1)` },
      { q: 'Microwaves are used in mobile phone communications. Explain why this part of the EM spectrum is suitable.', marks: 4, markScheme: `• Microwaves can pass through the atmosphere with little absorption (1)\n• They can be transmitted to and received from satellites (1)\n• Short wavelengths allow the use of small aerials in phones (1)\n• High frequencies allow large amounts of data to be transmitted (1)` },
      { q: 'Infrared radiation is used in thermal imaging cameras. Explain how these cameras work.', marks: 4, markScheme: `• All objects emit infrared (thermal) radiation (1)\n• Hotter objects emit more infrared and at shorter peak wavelengths (1)\n• The camera detects the infrared emitted and converts it to a false-colour image (1)\n• This shows the temperature distribution, allowing identification of people/animals in the dark or heat leaks in buildings (1)` },
      { q: 'Calculate the magnification of a lens that produces a 6.0 cm tall image of a 1.5 cm tall object. [Triple]', marks: 2, markScheme: `• m = image height ÷ object height = 6.0 ÷ 1.5 (1)\n• m = 4.0 (no units) (1)` },
      { q: 'Sketch a ray diagram for a converging lens used as a magnifying glass (object placed between F and the lens). State the nature of the image. [Triple]', marks: 5, diagram: true, markScheme: `• Convex lens drawn with principal axis and focal points F labelled (1)\n• Object drawn upright between the lens and F (1)\n• One ray parallel to axis refracts through F on far side (1)\n• One ray through the centre continues undeviated; both rays diverge on the far side — dashed construction lines drawn back on the object side (1)\n• Virtual, upright, magnified image drawn on the same side as the object (1)` },
      { q: 'Describe how the Earth maintains a roughly constant average temperature, using the idea of black-body radiation balance.', marks: 5, markScheme: `• The Earth absorbs electromagnetic radiation (mostly visible and UV) from the Sun (1)\n• The Earth re-emits thermal (infrared) radiation back into space (1)\n• When the rate of absorption equals the rate of emission, the temperature is constant (1)\n• If emission exceeds absorption the Earth cools; if absorption exceeds emission, the Earth warms (1)\n• Increased greenhouse gases absorb more emitted IR, causing warming (global warming/climate change) (1)` },
      { q: 'Explain why coloured filters appear their own colour when light passes through them. [Triple]', marks: 4, markScheme: `• A coloured filter absorbs some wavelengths of light (1)\n• It transmits only light of its own colour (or a narrow range around it) (1)\n• E.g. a red filter absorbs all colours except red, which passes through (1)\n• In blue light, a red filter appears black because there is no red light to transmit (1)` },
      { q: 'Describe a method to measure the speed of sound in air in the laboratory.', marks: 5, markScheme: `• Place two microphones a known distance d apart on a bench (1)\n• Connect both microphones to an oscilloscope or timer that starts with the first microphone and stops with the second (1)\n• Produce a sharp sound (hand clap or hammer strike) near the first microphone (1)\n• Record the time t for the sound to reach the second microphone (1)\n• Speed = d ÷ t; repeat and average to reduce random error (1)` },

      // --- Extended / 6-8 marks ---
      { q: 'Describe how a student could investigate the relationship between the angle of incidence and angle of refraction at a glass block boundary. [6 marks]', marks: 6, markScheme: `• Place a rectangular glass block on paper and draw around it (1)\n• Draw a normal at one face of the block (1)\n• Shine a ray of light at chosen angles of incidence to the normal (using a ray box) (1)\n• Mark the incident ray and the emerging ray; remove block and draw the refracted ray (1)\n• Measure angles of incidence and refraction with a protractor, for a range of incident angles (1)\n• Tabulate and plot refraction angle against incidence angle; angles of refraction are always smaller than angles of incidence (towards normal on entry) (1)` },
      { q: 'Compare the properties and uses of radio waves, visible light and X-rays, explaining how their different wavelengths make them suitable for different applications. [6 marks]', marks: 6, markScheme: `• Radio waves have long wavelengths and low frequencies — easily diffract around obstacles (1)\n• Used for TV, radio broadcasting and some wireless communication (1)\n• Visible light has medium wavelength; detected by the eye; used for sight and photography (1)\n• Visible light reflects off and is absorbed by objects, allowing images to be seen (1)\n• X-rays have very short wavelengths and high frequencies — high energy allows them to pass through soft tissue (1)\n• Used to image bones and in airport security; must be used carefully because X-rays are ionising and damage cells (1)` },
      { q: 'Evaluate the benefits and risks of using ultraviolet radiation for tanning and in fluorescent lamps. [6 marks]', marks: 6, markScheme: `• Benefits: UV stimulates production of vitamin D in skin (1)\n• Moderate tanning causes melanin production, protecting skin (1)\n• Fluorescent lamps absorb UV and re-emit visible light — more efficient than filament bulbs (1)\n• Risks: UV is ionising and can damage DNA in skin cells (1)\n• Overexposure causes sunburn, premature skin ageing and skin cancer (1)\n• Overall: UV has benefits but exposure should be limited; sunscreen and protective eyewear reduce the risks (1)` },
      { q: 'Sketch a detailed ray diagram for a converging lens with an object at 2F, showing exactly where the image forms. State three properties of the image. [6 marks]', marks: 6, diagram: true, markScheme: `• Lens drawn as convex with principal axis and focal points F and 2F labelled on both sides (1)\n• Object drawn as an upright arrow at 2F on the left side (1)\n• Ray 1: parallel to axis, refracting through F on the far side (1)\n• Ray 2: through the centre of the lens, undeviated (1)\n• Rays meet at 2F on the opposite side — image drawn as an inverted arrow (1)\n• Image properties: real, inverted, same size as object (1)` },
      { q: 'Explain how the colour of an opaque object depends on both its surface and the light illuminating it, using examples. [6 marks]', marks: 6, markScheme: `• Opaque objects absorb some wavelengths of light and reflect others (1)\n• A white object reflects all visible wavelengths; a black object absorbs all (1)\n• In white light, a green object reflects only green and absorbs all other colours (1)\n• In red light, that green object would absorb the red and appear dark/black (1)\n• The perceived colour depends on which wavelengths are reflected AND which are present in the incident light (1)\n• Filters and coloured lights exploit this effect — e.g. stage lighting in theatres can change how objects appear (1)` },
    ]
  },
  '4.7': {
    name: 'Magnetism and Electromagnetism',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'State what is meant by a permanent magnet.', marks: 1, markScheme: `• A material that produces its own magnetic field at all times (always magnetic) (1)` },
      { q: 'State what is meant by an induced magnet.', marks: 2, markScheme: `• A material that becomes a magnet when placed in another magnetic field (1)\n• It loses most or all of its magnetism when removed from the field (1)` },
      { q: 'State the rule for how magnetic poles interact.', marks: 2, markScheme: `• Like poles repel (1)\n• Unlike poles attract (1)` },
      { q: 'State the direction of magnetic field lines relative to a bar magnet.', marks: 2, markScheme: `• From north pole to south pole outside the magnet (1)\n• From south to north inside the magnet (forming closed loops); closer lines = stronger field (1)` },
      { q: 'State Fleming\'s left-hand rule and what each finger represents.', marks: 2, markScheme: `• ThuMb = direction of Motion (force); First finger = Field; seCond finger = Current (1)\n• Fingers are held mutually at right angles to give the direction of the force on a current-carrying conductor in a magnetic field (1)` },
      { q: 'State the equation for the force on a current-carrying conductor in a magnetic field. [Higher]', marks: 1, markScheme: `• F = B × I × L (force = magnetic flux density × current × length of conductor) (1)` },
      { q: 'State the equation relating primary and secondary voltages and turns in an ideal transformer. [Triple]', marks: 1, markScheme: `• V_p ÷ V_s = N_p ÷ N_s (primary/secondary voltages ratio equals the primary/secondary turns ratio) (1)` },
      { q: 'State two uses of electromagnets.', marks: 2, markScheme: `• Any two of: scrapyard cranes, maglev trains, electric bells/doorbells, relays, loudspeakers, MRI scanners, circuit breakers (1)(1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'Sketch the magnetic field lines around a bar magnet, showing the direction of the field.', marks: 4, diagram: true, markScheme: `• Bar magnet drawn with N and S poles labelled (1)\n• Field lines shown as curved lines looping from N to S outside the magnet (1)\n• Arrows on each field line pointing from N to S (1)\n• Field lines closer together near the poles (stronger field at poles); symmetrical pattern (1)` },
      { q: 'Sketch the magnetic field pattern between two bar magnets with opposite poles facing each other.', marks: 3, diagram: true, markScheme: `• Two bar magnets drawn in line with N facing S (1)\n• Field lines drawn from N of one magnet curving across to S of the other (1)\n• Arrows indicate direction of field; lines run from N to S (no repulsion pattern) (1)` },
      { q: 'Sketch the magnetic field around a long straight current-carrying wire, showing how to use the right-hand grip rule.', marks: 4, diagram: true, markScheme: `• Vertical wire drawn with arrow showing direction of conventional current (1)\n• Concentric circles drawn around the wire showing the field lines (1)\n• Arrows on field circles showing direction (consistent with right-hand grip rule) (1)\n• Indication that field weakens with distance (lines further apart); right-hand rule: thumb = current, fingers curl = field direction (1)` },
      { q: 'Sketch the magnetic field around a solenoid carrying a current, and describe the field inside.', marks: 4, diagram: true, markScheme: `• Solenoid drawn as a coil of wire with current direction indicated (1)\n• Field pattern outside like a bar magnet with identified N and S ends (1)\n• Uniform, straight, parallel field lines inside the solenoid in the same direction (1)\n• Field inside is strong and uniform; field outside is weaker (1)` },
      { q: 'Describe how to make an electromagnet and how its strength can be increased.', marks: 4, markScheme: `• Wind an insulated wire into a coil around an iron core (1)\n• Pass a current through the coil — the iron core becomes magnetised while current flows (1)\n• Increase strength by: increasing the current (1)\n• Or increasing the number of turns in the coil / using a softer iron core (1)` },
      { q: 'Describe how a compass can be used to plot the magnetic field around a bar magnet.', marks: 3, markScheme: `• Place the bar magnet on paper and mark its position (1)\n• Put a plotting compass near the magnet and mark dots at each end of the compass needle (1)\n• Move the compass to the new position and repeat — join the dots into a smooth line with an arrow showing direction (from N to S outside the magnet) (1)` },
      { q: 'Explain why a current-carrying wire in a magnetic field experiences a force. [Higher]', marks: 4, markScheme: `• The current-carrying wire produces its own magnetic field (1)\n• This field interacts with the external magnetic field (1)\n• The two fields combine — stronger on one side of the wire and weaker on the other (1)\n• The wire experiences a force from the strong side towards the weaker side (the motor effect); F = BIL (1)` },
      { q: 'A 0.20 m wire carrying a current of 4.0 A is placed at right angles to a magnetic field of flux density 0.15 T. Calculate the force on the wire. [Higher]', marks: 3, markScheme: `• F = B × I × L (1)\n• F = 0.15 × 4.0 × 0.20 (1)\n• F = 0.12 N (1)` },
      { q: 'Sketch a simple d.c. motor showing the coil, magnets, split-ring commutator and brushes. Indicate the direction of rotation.', marks: 5, diagram: true, markScheme: `• Rectangular coil drawn between north and south poles of a permanent magnet (1)\n• Split-ring commutator drawn on the axis of the coil (1)\n• Two carbon brushes drawn in contact with the split-ring (1)\n• Current direction through the coil indicated and forces on opposite sides drawn in opposite directions (1)\n• Arrow showing direction of rotation consistent with Fleming\'s left-hand rule (1)` },
      { q: 'Explain how a split-ring commutator ensures that a d.c. motor rotates continuously in the same direction.', marks: 4, markScheme: `• As current flows through the coil, opposite sides experience forces in opposite directions (one up, one down) — the coil rotates (1)\n• After half a turn, the sides are swapped; if the current continued in the same direction the forces would reverse the rotation (1)\n• The split-ring commutator reverses the current direction in the coil every half turn (1)\n• This ensures the force on each side always acts in the direction that keeps the coil rotating the same way (1)` },
      { q: 'Describe the motor effect and state two factors that affect the size of the force on a current-carrying conductor. [Higher]', marks: 4, markScheme: `• When a current-carrying conductor is placed in a magnetic field, it experiences a force (1)\n• The force is maximum when the conductor is at 90° to the field (1)\n• Force increases with larger current in the conductor (1)\n• Force increases with stronger magnetic flux density B (or longer conductor L) (1)` },
      { q: 'Explain how a loudspeaker uses the motor effect to produce sound. [Triple]', marks: 4, markScheme: `• An alternating current from an amplifier flows through a coil attached to a cone (1)\n• The coil sits in a permanent magnetic field; the current in the field produces a force (motor effect) (1)\n• As the current alternates, the force on the coil reverses, making the coil (and cone) vibrate back and forth (1)\n• The vibrating cone creates sound waves at the same frequency as the a.c. (1)` },
      { q: 'Explain the difference between a transformer and an electromagnet.', marks: 3, markScheme: `• An electromagnet is a coil (usually around an iron core) that produces a magnetic field when a current flows; used to exert a magnetic force (1)\n• A transformer consists of two coils linked by a common iron core and is used to change the voltage of an a.c. supply (1)\n• Transformers only work with a.c., whereas an electromagnet can work on d.c. (1)` },
      { q: 'A transformer has 1000 turns on the primary coil and 200 turns on the secondary coil. The primary voltage is 230 V. Calculate the secondary voltage. [Triple]', marks: 3, markScheme: `• V_p ÷ V_s = N_p ÷ N_s (1)\n• V_s = V_p × (N_s ÷ N_p) = 230 × (200 ÷ 1000) (1)\n• V_s = 46 V (step-down transformer) (1)` },
      { q: 'Sketch a diagram of a basic transformer, labelling the primary coil, secondary coil and iron core. [Triple]', marks: 4, diagram: true, markScheme: `• Rectangular iron core drawn as a laminated square (1)\n• Primary coil labelled with its turns N_p on one side (1)\n• Secondary coil labelled with its turns N_s on the other side (1)\n• a.c. input indicated on primary, output on secondary; arrow indicating changing magnetic flux linking the two coils through the core (1)` },

      // --- Application (4-5 marks) ---
      { q: 'Describe the generator effect and state two ways of inducing a potential difference in a coil. [Triple]', marks: 4, markScheme: `• A potential difference is induced when there is relative movement between a conductor and a magnetic field (1)\n• Moving a magnet into or out of a coil induces a pd (1)\n• Moving a conductor through a magnetic field induces a pd (1)\n• Alternating the magnetic field through a coil (e.g. from an a.c. source) also induces a pd; direction of induced pd opposes the change (Lenz\'s law) (1)` },
      { q: 'Describe how the induced potential difference changes when a magnet is pushed into a coil, and how to increase its size. [Triple]', marks: 5, markScheme: `• Pushing the magnet into the coil induces a pd across the coil (1)\n• The induced pd opposes the change — the coil acts like a magnet to repel the incoming magnet (1)\n• Increase the induced pd by moving the magnet faster (1)\n• Increase the number of turns on the coil (1)\n• Use a stronger magnet (or add an iron core) (1)` },
      { q: 'Sketch output traces for an a.c. generator (with slip rings) and a d.c. dynamo (with split-ring commutator). [Triple]', marks: 5, diagram: true, markScheme: `• Both traces drawn on voltage vs time axes (1)\n• a.c. generator: smooth sinusoidal curve going above and below zero (1)\n• d.c. dynamo: rectified sinusoidal curve — all half-waves on the positive side (1)\n• Same frequency shown on both traces (1)\n• Slip-rings and split-ring commutator labelled as the cause of the difference (1)` },
      { q: 'Explain why a transformer will not work with direct current. [Triple]', marks: 4, markScheme: `• Direct current produces a constant (unchanging) magnetic flux in the iron core (1)\n• An induced pd requires the magnetic flux in the secondary coil to be changing (1)\n• With a steady flux, there is no change — so no pd is induced in the secondary coil (1)\n• A.c. produces a continually changing flux, which induces an alternating pd in the secondary coil (1)` },
      { q: 'A transformer has 500 turns on the primary and 2000 turns on the secondary. If the primary current is 8.0 A and the transformer is 100% efficient, calculate the secondary current. [Triple]', marks: 4, markScheme: `• For 100% efficiency: V_p × I_p = V_s × I_s (1)\n• Turns ratio: V_s ÷ V_p = N_s ÷ N_p = 2000 ÷ 500 = 4 (1)\n• So V_s = 4 × V_p; from power balance I_s = I_p × (V_p ÷ V_s) = 8.0 ÷ 4 (1)\n• I_s = 2.0 A (step-up transformer: voltage up, current down) (1)` },
      { q: 'Explain why the National Grid uses step-up transformers for transmission and step-down transformers for domestic supply. [Triple]', marks: 5, markScheme: `• Step-up transformers increase the voltage (and reduce the current) for transmission across long distances (1)\n• Power loss in cables = I²R — lower current means much smaller heating losses (1)\n• This makes long-distance transmission much more efficient (1)\n• Very high voltages are dangerous for domestic use, so step-down transformers reduce the voltage back to 230 V (1)\n• The National Grid therefore delivers electricity efficiently and safely to consumers (1)` },
      { q: 'Sketch a labelled diagram of an a.c. generator, including the coil, magnets and slip rings. [Triple]', marks: 5, diagram: true, markScheme: `• Rectangular coil drawn between opposing N and S poles of a permanent magnet (1)\n• Axis of rotation drawn through the coil (1)\n• Two slip rings attached to the ends of the coil (not split) (1)\n• Two carbon brushes touching the slip rings, connected to the external circuit (1)\n• Label: rotation of the coil in the field induces an alternating pd in the coil (1)` },
      { q: 'Sketch a labelled diagram of a d.c. motor and explain how a current is able to rotate the coil.', marks: 5, diagram: true, markScheme: `• Rectangular coil between N and S poles of a permanent magnet (1)\n• Split-ring commutator on the coil\'s axis with two carbon brushes (1)\n• Current direction in the coil and the direction of force on each side indicated (1)\n• Explanation: opposite sides of the coil carry current in opposite directions in a field, so forces are equal and opposite — creating a couple (turning effect) (1)\n• Split-ring commutator reverses the current every half turn to keep rotation in one direction (1)` },
      { q: 'Explain why iron is used as the core of a transformer and why it is laminated. [Triple]', marks: 4, markScheme: `• Iron is easily magnetised and demagnetised (soft magnetic material) (1)\n• This makes the core a very effective magnetic link between the primary and secondary coils, increasing the induced pd (1)\n• Laminated layers are separated by insulation, reducing eddy currents in the core (1)\n• This reduces energy wasted as heat, increasing the transformer\'s efficiency (1)` },
      { q: 'A scrapyard uses an electromagnet to lift iron-based scrap. Explain the advantages of an electromagnet over a permanent magnet for this purpose.', marks: 4, markScheme: `• The electromagnet can be turned on to pick up scrap and off to release it by switching the current on/off (1)\n• The strength of the field can be controlled by adjusting the current (1)\n• Permanent magnets cannot be switched off — releasing the load would be difficult (1)\n• Electromagnets can be made much stronger than practical permanent magnets of the same size (1)` },
      { q: 'Sketch the magnetic field pattern between two bar magnets placed with like poles facing each other (N–N).', marks: 4, diagram: true, markScheme: `• Two bar magnets drawn in line with N poles facing each other (1)\n• Field lines leaving each N pole curving away — repulsion pattern (1)\n• A neutral point shown between the magnets where field lines do not pass (1)\n• Field lines symmetrical; arrows pointing away from both N poles (1)` },
      { q: 'A transformer steps down 11 000 V to 230 V for domestic supply. Calculate the ratio of turns on the secondary to the primary, and state whether it has more or fewer turns on the secondary. [Triple]', marks: 3, markScheme: `• N_s ÷ N_p = V_s ÷ V_p = 230 ÷ 11 000 (1)\n• N_s ÷ N_p = 1 ÷ 47.8 (≈ 1:48) (1)\n• Fewer turns on the secondary (step-down transformer) (1)` },
      // --- Extended / 6-8 marks ---
      { q: 'Describe how a transformer works, using the concept of electromagnetic induction and a changing magnetic field. [Triple, 6 marks]', marks: 6, markScheme: `• An alternating potential difference is applied to the primary coil (1)\n• This causes an alternating current in the primary coil (1)\n• The current creates an alternating magnetic field (changing flux) in the iron core (1)\n• The flux links the secondary coil through the core (1)\n• The changing flux induces an alternating pd across the secondary coil (electromagnetic induction) (1)\n• The ratio V_p/V_s equals N_p/N_s; assuming 100% efficiency, V_p × I_p = V_s × I_s (1)` },
      { q: 'Explain how electricity is efficiently transmitted across the National Grid, referring to transformers and I²R losses. [Triple, 6 marks]', marks: 6, markScheme: `• At the power station, a step-up transformer increases voltage to 132 kV or higher (1)\n• Power is transmitted as P = V × I, so increasing V means smaller I for the same P (1)\n• Power lost as heat in cables is I²R — reducing I reduces the losses dramatically (1)\n• Low losses make long-distance transmission practical and efficient (1)\n• Near homes, step-down transformers reduce the voltage to safer levels (e.g. 230 V) (1)\n• Overall efficient transmission balances electrical safety (low V at home) with efficient transport (high V in transmission lines) (1)` },
      { q: 'A d.c. motor is used to lift a load. Describe how the motor works and how it converts electrical energy into mechanical energy. [6 marks]', marks: 6, markScheme: `• The motor consists of a current-carrying coil between the poles of a permanent magnet (1)\n• Current in each side of the coil experiences a force in the magnetic field (motor effect) (1)\n• Forces on opposite sides of the coil are in opposite directions, creating a turning effect (couple) (1)\n• The split-ring commutator reverses the current direction every half-turn (1)\n• Carbon brushes keep contact between the commutator and the external supply (1)\n• The coil rotates continuously, transferring electrical energy to a rotating kinetic store that can do useful work (e.g. lifting a load) (1)` },
      { q: 'Compare an a.c. generator with a d.c. dynamo, describing their construction and the outputs produced. [Triple, 6 marks]', marks: 6, diagram: true, markScheme: `• Both have a coil rotating in a magnetic field (1)\n• A.c. generator uses two slip rings connected one to each end of the coil (1)\n• D.c. dynamo uses a split-ring commutator (1)\n• Output traces drawn: a.c. as sine wave crossing zero, d.c. as rectified humps (always same polarity) (1)\n• The frequency of both outputs equals the rotational frequency of the coil (1)\n• The commutator in the dynamo reverses connections every half turn to keep the output polarity the same; slip rings in the a.c. generator do not (1)` },
      { q: 'Evaluate the use of electromagnets over permanent magnets in everyday devices such as relays, doorbells and cranes. [6 marks]', marks: 6, markScheme: `• Electromagnets can be switched on and off with a current — essential for relays and cranes (1)\n• Strength can be varied by changing the current or number of turns — versatile (1)\n• Can be made very strong for a given size, e.g. industrial cranes and MRI scanners (1)\n• Require a continuous current to maintain the field — consume energy and generate heat (1)\n• If the power fails, the magnet field disappears, which can be a safety issue or a safety feature (fail-safe release) (1)\n• Permanent magnets are simpler and need no power but cannot be turned off — fine for compasses and fridge magnets but unsuitable for controlled applications (1)` },
    ]
  },
  '4.8': {
    name: 'Space Physics',
    questions: [
      // --- Recall (1-2 marks) ---
      { q: 'Name the galaxy that contains our solar system.', marks: 1, markScheme: `• The Milky Way (1)` },
      { q: 'State the eight planets of our solar system in order from the Sun.', marks: 2, markScheme: `• Mercury, Venus, Earth, Mars (1)\n• Jupiter, Saturn, Uranus, Neptune (1)` },
      { q: 'State what is meant by a natural satellite and give an example.', marks: 2, markScheme: `• A natural satellite is a body in orbit around a planet (a moon) (1)\n• Example: the Moon orbits the Earth (1)` },
      { q: 'State what is meant by a galaxy.', marks: 1, markScheme: `• A large collection of many billions of stars held together by gravity (1)` },
      { q: 'State the approximate age of the universe according to the Big Bang theory.', marks: 1, markScheme: `• Approximately 13.8 billion years (1)` },
      { q: 'State two pieces of evidence for the Big Bang theory.', marks: 2, markScheme: `• Red-shift of light from distant galaxies showing the universe is expanding (1)\n• Cosmic microwave background radiation (CMBR) — a uniform microwave glow filling space (1)` },
      { q: 'State what is meant by red-shift.', marks: 2, markScheme: `• The observed wavelength of light from a receding source is longer than the emitted wavelength (1)\n• The light is shifted towards the red end of the visible spectrum (1)` },
      { q: 'State the relationship between gravitational force and centripetal force for an object in a stable orbit.', marks: 2, markScheme: `• The gravitational force provides the centripetal force (1)\n• The gravitational force is always directed toward the central body (1)` },

      // --- Describe / Explain / Calculate (3-4 marks) ---
      { q: 'Sketch a labelled diagram of the solar system showing the Sun, the eight planets in order, and the asteroid belt.', marks: 4, diagram: true, markScheme: `• Sun drawn at the centre, labelled (1)\n• Eight planets drawn in correct order: Mercury, Venus, Earth, Mars, Jupiter, Saturn, Uranus, Neptune (1)\n• Asteroid belt shown between Mars and Jupiter (1)\n• Planets clearly labelled; orbits shown as roughly circular/elliptical paths (1)` },
      { q: 'Describe how the Sun was formed approximately 5 billion years ago.', marks: 4, markScheme: `• A large cloud of dust and gas (nebula) was pulled together by gravity (1)\n• As the cloud collapsed, its temperature and pressure increased (1)\n• Eventually the core became hot enough for nuclear fusion of hydrogen into helium (1)\n• The Sun became a main sequence star, releasing energy from fusion (1)` },
      { q: 'Describe the stages of the life cycle of a star the same size as the Sun.', marks: 5, markScheme: `• Nebula — gravity pulls dust and gas together (1)\n• Protostar — compression raises temperature until hydrogen fusion begins (1)\n• Main sequence — stable stage where inward gravity balances outward radiation pressure from fusion (1)\n• Red giant — hydrogen runs low; outer layers expand and cool while helium fuses to heavier elements up to carbon/oxygen (1)\n• White dwarf (after planetary nebula ejected) — hot, dense remnant that cools over time to a black dwarf (1)` },
      { q: 'Describe the life cycle of a star much more massive than the Sun.', marks: 5, markScheme: `• Nebula → protostar → main sequence (fusion of hydrogen to helium) (1)\n• When hydrogen runs out, it expands to form a red supergiant (1)\n• Fusion continues producing elements up to iron in the core (1)\n• Red supergiant explodes as a supernova, scattering heavier elements into space (1)\n• Remnant becomes a neutron star, or — if very massive — a black hole (1)` },
      { q: 'Sketch a flow chart for the life cycle of a low-mass star and a high-mass star from nebula onwards.', marks: 5, diagram: true, markScheme: `• Start: nebula → protostar → main sequence (branch) (1)\n• Low mass branch: red giant → planetary nebula + white dwarf → black dwarf (1)\n• High mass branch: red supergiant → supernova → neutron star (1)\n• Very high mass branch from supernova: black hole (1)\n• Arrows correctly linking each stage; labels clear (1)` },
      { q: 'Explain how elements heavier than iron are formed and distributed throughout the universe.', marks: 4, markScheme: `• Elements up to iron are formed by nuclear fusion in stars during their lifetimes (1)\n• Elements heavier than iron require higher energies than ordinary fusion provides (1)\n• They are formed only in supernova explosions (1)\n• The explosion distributes these heavy elements across space, later forming new stars and planets (including Earth, which contains heavy elements) (1)` },
      { q: 'Explain how the balance of forces in a main sequence star keeps it stable.', marks: 4, markScheme: `• Gravity acts inward, pulling material towards the centre (1)\n• Fusion in the core releases energy, creating outward radiation pressure (1)\n• These two forces are balanced — the star does not collapse or expand (1)\n• This state is maintained while the star has enough hydrogen fuel in its core (1)` },
      { q: 'Sketch a diagram showing an object in a stable orbit around a planet, with arrows showing velocity and gravitational (centripetal) force.', marks: 4, diagram: true, markScheme: `• Central planet drawn with orbital path shown around it (1)\n• Object drawn on the orbit (1)\n• Velocity arrow drawn tangent to the orbit at the object (1)\n• Gravitational force arrow drawn from the object towards the centre of the planet (perpendicular to velocity) (1)` },
      { q: 'Explain why an object in a stable circular orbit is constantly accelerating, even though its speed is constant.', marks: 4, markScheme: `• Velocity is a vector — it has both magnitude and direction (1)\n• In a circular orbit the direction of motion is constantly changing (1)\n• A change in velocity is acceleration (even if speed is constant) (1)\n• The acceleration is directed towards the centre of the orbit, caused by the gravitational force (centripetal) (1)` },
      { q: 'State and explain the relationship between orbital speed and orbital radius for a satellite.', marks: 3, markScheme: `• At a given altitude there is one fixed orbital speed for a stable circular orbit (1)\n• A lower (smaller-radius) orbit requires a higher orbital speed (1)\n• A higher orbit requires a lower orbital speed; a faster object at a given altitude would have too much kinetic energy and spiral outwards / escape (1)` },
      { q: 'Describe what is meant by red-shift and what it tells us about distant galaxies.', marks: 4, markScheme: `• Red-shift is the increase in the observed wavelength of light from a receding source (1)\n• Absorption/emission lines in the spectrum of distant galaxies are shifted toward the red end (1)\n• Most distant galaxies show red-shift, meaning they are moving away from us (1)\n• The more distant the galaxy, the greater the red-shift, so the faster it is receding — evidence for an expanding universe (1)` },
      { q: 'Sketch a diagram showing the spectral lines of a stationary source and those of a galaxy receding from us. Label the red-shift.', marks: 4, diagram: true, markScheme: `• Two horizontal spectrum strips drawn one above the other with wavelength axis (violet/blue → red direction) (1)\n• Stationary source shown with absorption/emission lines at reference positions (1)\n• Distant galaxy shown with lines at longer wavelengths (shifted toward red end) (1)\n• Arrow and label: "red-shift" showing the shift of corresponding lines towards the red end (1)` },
      { q: 'Describe what cosmic microwave background radiation (CMBR) is and why it supports the Big Bang theory.', marks: 4, markScheme: `• CMBR is a low-energy microwave radiation that comes uniformly from all directions in space (1)\n• It is the leftover radiation from the very hot early universe, after it had cooled enough for light to travel freely (1)\n• The Big Bang theory predicted its existence (1)\n• Its detection (and uniformity/spectrum) is strong evidence that the universe began as a very hot, dense state (1)` },
      { q: 'Explain what is meant by dark matter and why scientists think it exists.', marks: 3, markScheme: `• Dark matter is matter that does not emit or absorb light — it cannot be detected directly (1)\n• Galaxies rotate faster than expected from the visible matter (rotation curves don\'t match prediction) (1)\n• Extra mass from unseen (dark) matter is needed to explain the gravitational effects observed in galaxies (1)` },
      { q: 'Explain what is meant by dark energy and why it was proposed.', marks: 3, markScheme: `• Dark energy is a form of energy thought to fill all of space (1)\n• Observations show that the expansion of the universe is accelerating (1)\n• Dark energy is proposed to provide the repulsive effect that drives this accelerating expansion (1)` },

      // --- Application (4-5 marks) ---
      { q: 'Explain why a satellite can remain in a stable orbit around the Earth while constantly changing direction.', marks: 5, markScheme: `• Gravity between the Earth and satellite pulls the satellite towards the Earth\'s centre (1)\n• This gravitational force provides the centripetal force (1)\n• The satellite moves tangentially to its orbit at high speed (1)\n• Gravity continually changes the direction of motion — the satellite falls around the Earth rather than into it (1)\n• Speed is constant in a circular orbit but velocity changes (direction) — so the satellite is always accelerating towards the centre (1)` },
      { q: 'The Sun will eventually become a white dwarf. Describe the stages it will go through and the final state.', marks: 5, markScheme: `• Hydrogen in the core will run low, causing the Sun to expand into a red giant (1)\n• Helium and heavier elements (up to carbon/oxygen) will fuse in its core (1)\n• Eventually outer layers will be ejected as a planetary nebula (1)\n• The hot dense core left behind is a white dwarf (1)\n• Over billions of years the white dwarf cools to a black dwarf (theoretically) (1)` },
      { q: 'Explain how Hubble\'s observations of galaxies led to the theory that the universe is expanding.', marks: 5, markScheme: `• Hubble measured the distances to many galaxies and the red-shift of their light (1)\n• He found that almost all galaxies show red-shift (they are receding) (1)\n• More distant galaxies have a larger red-shift (1)\n• This means more distant galaxies are moving away faster (1)\n• This is consistent with a universe that is expanding in all directions — leading to the Big Bang theory (1)` },
      { q: 'Sketch a diagram showing the orbit of a comet compared to that of a planet around the Sun. Describe the difference in speed at different points.', marks: 5, diagram: true, markScheme: `• Sun drawn at a focus (1)\n• Planet orbit drawn as nearly circular (1)\n• Comet orbit drawn as a highly elongated ellipse around the Sun (1)\n• Label showing comet moves fastest when closest to the Sun (perihelion) (1)\n• Comet moves slowest when furthest from the Sun (aphelion) — due to changing radius, the gravitational force and so orbital speed change (1)` },
      { q: 'Compare the final stages of a low-mass star (like the Sun) and a high-mass star.', marks: 5, markScheme: `• Low-mass: expands to a red giant after the main sequence (1)\n• Ejects outer layers as a planetary nebula; remnant is a white dwarf that cools to a black dwarf (1)\n• High-mass: expands to a red supergiant, with fusion producing elements up to iron (1)\n• Explodes as a supernova — scattering heavy elements (1)\n• Leaves behind either a neutron star or, for the most massive stars, a black hole (1)` },
      { q: 'Explain why nuclear fusion in stars cannot produce elements heavier than iron.', marks: 4, markScheme: `• Fusion of nuclei lighter than iron releases energy — the product is more stable (1)\n• Fusion to form elements heavier than iron absorbs energy rather than releasing it (1)\n• A star\'s core cannot sustain this energy-absorbing reaction (1)\n• Heavier elements are only formed in the extreme conditions of a supernova explosion (1)` },
      { q: 'Sketch a diagram illustrating the relative sizes and orbits of the Sun, a planet and a moon, and explain the terms natural satellite and artificial satellite.', marks: 5, diagram: true, markScheme: `• Sun drawn at centre with a planet in orbit around it (1)\n• Moon drawn in orbit around the planet (1)\n• Clear arrows showing orbital motion (1)\n• Natural satellite: a naturally-occurring body orbiting a planet, e.g. the Moon (1)\n• Artificial satellite: a human-made object placed in orbit, e.g. the ISS or a communication satellite (1)` },
      { q: 'Describe the key stages from a nebula to a main sequence star, including the forces and reactions involved.', marks: 5, markScheme: `• A nebula is a large cloud of dust and gas in space (1)\n• Gravity pulls the cloud together, causing it to contract (1)\n• As the cloud collapses, gravitational potential energy is transferred to thermal energy — temperature and pressure rise (protostar) (1)\n• When the core becomes hot and dense enough, hydrogen fuses to helium (1)\n• The outward radiation pressure from fusion balances inward gravity — the star is on the main sequence (stable) (1)` },
      { q: 'Explain, using conservation of momentum and centripetal force ideas, why a satellite must travel faster in a lower orbit than in a higher orbit.', marks: 4, markScheme: `• Gravitational force provides the centripetal force: F = mv² ÷ r (1)\n• Gravity is stronger at smaller r (closer to the planet) (1)\n• A larger centripetal force requires a larger v² for the given r (1)\n• Therefore a satellite in a lower orbit has a higher orbital speed than one in a higher orbit (1)` },
      { q: 'Describe why scientists think the solar system formed from the remains of an earlier supernova.', marks: 4, markScheme: `• Earth contains heavy elements (beyond iron) — e.g. gold, uranium (1)\n• Heavy elements can only be produced in supernovae (1)\n• Therefore the material forming the solar system must have been enriched by at least one previous supernova (1)\n• The nebula that formed the Sun contained this material, which went on to make planets including the Earth (1)` },
      { q: 'Sketch a diagram showing red-shift of light from three galaxies at different distances. Describe the conclusion that can be drawn.', marks: 5, diagram: true, markScheme: `• Reference spectrum of a nearby (or stationary) source drawn at the top with characteristic absorption lines (1)\n• Galaxy A (closer) with small red-shift — lines slightly shifted toward red (1)\n• Galaxy B (further) with larger red-shift — lines further to red (1)\n• Galaxy C (furthest) with largest red-shift (1)\n• Conclusion: more distant galaxies recede faster — evidence that the universe is expanding (1)` },
      { q: 'Explain how changing the orbital speed of a satellite could cause it to move to a different orbit.', marks: 4, markScheme: `• At a given altitude there is one stable orbital speed (1)\n• If a satellite speeds up, it has more kinetic energy and rises to a higher orbit (1)\n• In the higher orbit, it needs a lower orbital speed to be stable (1)\n• If it slows down, it falls to a lower orbit, which requires a higher speed — if speed is still too low it will re-enter the atmosphere (1)` },

      // --- Extended / 6-8 marks ---
      { q: 'Describe and explain the complete life cycle of a high-mass star from nebula to black hole, including the nuclear reactions that occur at each stage. [6 marks]', marks: 6, markScheme: `• Nebula — gravity pulls dust and gas together to form a protostar (1)\n• Main sequence — hydrogen fuses to helium; radiation pressure balances gravity (1)\n• Red supergiant — when hydrogen runs out, the star expands; helium fuses to heavier elements up to iron (1)\n• Supernova — the star explodes, fusing and scattering elements heavier than iron (1)\n• A neutron star forms from the collapsed core (1)\n• For the most massive stars, gravity is so strong the core collapses further to a black hole (1)` },
      { q: 'Evaluate the evidence for the Big Bang theory, including red-shift, CMBR and current observations. [6 marks]', marks: 6, markScheme: `• Red-shift of distant galaxies shows the universe is expanding in all directions (1)\n• Greater red-shift for more distant galaxies shows faster recession — consistent with uniform expansion from a single origin (1)\n• Cosmic microwave background radiation is a uniform microwave glow predicted by the Big Bang (1)\n• CMBR represents radiation from the early hot universe that has cooled as the universe expanded (1)\n• The Big Bang theory accounts for the observed abundance of light elements (H and He) (1)\n• The theory is supported by multiple independent lines of evidence and is currently the accepted model, though dark matter and dark energy remain active areas of research (1)` },
      { q: 'Explain how observations of galaxies and the CMBR support the theory that the universe has been expanding since the Big Bang. [6 marks]', marks: 6, diagram: true, markScheme: `• Light from galaxies shows a red-shift — absorption lines are at longer wavelengths than expected (1)\n• Sketch: spectrum of stationary vs receding galaxy with shift clearly marked (1)\n• More distant galaxies show greater red-shift — they are moving away faster (1)\n• This is consistent with space itself expanding, with galaxies carried apart (1)\n• The CMBR is a uniform microwave glow predicted by the Big Bang theory — the afterglow of the hot early universe (1)\n• Together, red-shift and CMBR provide strong evidence that the universe has been expanding from a hot dense state for ~13.8 billion years (1)` },
      { q: 'A satellite in a circular orbit around the Earth is moved to a higher orbit. Describe how its orbital speed, period and gravitational force change. [6 marks]', marks: 6, markScheme: `• In a higher orbit, the satellite is further from the Earth\'s centre (1)\n• Gravitational force is weaker because F ∝ 1/r² (inverse-square law) (1)\n• A smaller centripetal force is needed, so orbital speed is lower (1)\n• The orbital period T (time to complete one orbit) is longer (1)\n• This is because the circumference of the orbit is larger AND the orbital speed is smaller (1)\n• Geostationary satellites orbit at a specific altitude where T = 24 hours, staying above the same point on the Earth (1)` },
      { q: 'Compare and contrast the physics of natural satellites, artificial satellites and comets in their orbits. [8 marks]', marks: 8, markScheme: `Award up to 8 marks for a balanced discussion:\n\n• All are held in orbit by gravity acting as a centripetal force towards the central body (1)\n• Natural satellites (moons) orbit planets in mostly near-circular, stable orbits (1)\n• Artificial satellites are human-made; their orbits depend on purpose: low Earth orbit for imaging, geostationary for communication (1)\n• Artificial satellites can be moved to different orbits by adjusting speed (increasing → higher orbit, decreasing → lower) (1)\n• Comets orbit the Sun in highly elongated elliptical paths (1)\n• Comets travel fastest near the Sun (perihelion) and slowest far away (aphelion) — gravitational force varies with distance (1)\n• For circular orbits: speed and distance are constant; for elliptical orbits they change (1)\n• Conservation of energy: KE and GPE exchange during the orbit of a comet — total orbital energy remains constant (1)` },
    ]
  },
};
